<?php
require_once 'config.php';
require_login();
$user = get_session_user();
$empId = get_hrms_emp_id();
// Server-side fetch for initial render — HRMS primary, EP DB fallback
$profile = hrms_api_call('/api/get_employee_full_profile', ['id' => $empId]);
if (!$profile) { $profile = []; }

// Fallback: if HRMS data is empty/missing, fill from employee_profile_db
if (empty($profile['name']) || empty($profile['email'])) {
    try {
        $epDb = get_ep_db();
        $epStmt = $epDb->prepare("SELECT first_name, last_name, email, phone, profile_picture_url, role FROM users WHERE hrms_employee_id = ? LIMIT 1");
        $epStmt->execute([$empId]);
        $epUser = $epStmt->fetch(PDO::FETCH_ASSOC);
        if ($epUser) {
            if (empty($profile['name']))    $profile['name'] = $epUser['first_name'];
            if (empty($profile['last_name'])) $profile['last_name'] = $epUser['last_name'];
            if (empty($profile['email']))   $profile['email'] = $epUser['email'];
            if (empty($profile['contact'])) $profile['contact'] = $epUser['phone'];
            if (empty($profile['profile'])) $profile['profile'] = $epUser['profile_picture_url'];
        }
    } catch (PDOException $ex) {
        // Silently fall through — profile may show partial data
    }
}

// Also fetch division/department from HRMS DB if API didn't return them
if (empty($profile['division_name']) || empty($profile['dept_department_name'])) {
    try {
        if (!isset($hrmsDb)) {
            $hrmsDb = get_hrms_db();
        }
        $posStmt = $hrmsDb->prepare("
            SELECT e.client_id, e.profile, e.profile_storage,
                   p.positionTitle, dm.dept_department_name, dv.divn_division_name AS division_name,
                   jm.job_job_title
            FROM employee e
            LEFT JOIN positions p ON p.positionID = e.position_id
            LEFT JOIN job_masters jm ON jm.job_job_id = e.job_id
            LEFT JOIN departments_master dm ON dm.dept_department_id = p.department_id
            LEFT JOIN divisions_master dv ON dv.divn_division_id = p.division_id
            WHERE e.empID = ? LIMIT 1
        ");
        $posStmt->execute([$empId]);
        $posData = $posStmt->fetch(PDO::FETCH_ASSOC);
        if ($posData) {
            if (empty($profile['positionTitle']))       $profile['positionTitle'] = $posData['positionTitle'];
            if (empty($profile['dept_department_name'])) $profile['dept_department_name'] = $posData['dept_department_name'];
            if (empty($profile['division_name']))       $profile['division_name'] = $posData['division_name'];
            if (empty($profile['client_id']))           $profile['client_id'] = $posData['client_id'];
            if (empty($profile['profile_storage']))     $profile['profile_storage'] = $posData['profile_storage'];
            // Override profile photo from DB (freshest source)
            if (!empty($posData['profile']))            $profile['profile'] = $posData['profile'];
        }
    } catch (PDOException $ex) {
        // Silently fall through
    }
}

// Compute profile picture URL (FileStorage viewFile URL or legacy path)
$profilePicUrl = profile_pic_url($profile);
if (empty($profilePicUrl)) $profilePicUrl = '';

// ── Fetch role-based left menu from HRMS DB ──
$hrmsMenuItems = [];
$hrmsRoleId = null;
try {
    if (!isset($hrmsDb)) {
        $hrmsDb = get_hrms_db();
    }
    // Get employee's role_id
    $roleStmt = $hrmsDb->prepare("SELECT role_id FROM employee WHERE empID = ? LIMIT 1");
    $roleStmt->execute([$empId]);
    $hrmsRoleId = $roleStmt->fetchColumn();

    if ($hrmsRoleId) {
        // Fetch top-level menu items only (flat menu, no submenus)
        $menuStmt = $hrmsDb->prepare("
            SELECT ms.id, ms.module_name, ms.url, ms.display_order,
                   ms.external_link, ms.link_open_in,
                   si.svgi_icon_file, si.svgi_icon_svg
            FROM menu_setting ms
            LEFT JOIN svg_icons_master si ON si.svgi_icon_id = ms.iconID
            WHERE ms.role_id = ? AND ms.parent_id = 0
            ORDER BY ms.display_order ASC
        ");
        $menuStmt->execute([$hrmsRoleId]);
        $hrmsMenuItems = $menuStmt->fetchAll(PDO::FETCH_ASSOC);
    }
    // ── Fetch site settings (logo, favicon) ──
    $siteStmt = $hrmsDb->query("SELECT logo, favicon FROM settings LIMIT 1");
    $siteCfg = $siteStmt->fetch(PDO::FETCH_ASSOC);
} catch (PDOException $ex) {
    // Silently fall through — static fallback menu will be used
}
$hrmsLogo   = !empty($siteCfg['logo'])    ? HRMS_BASE . '/uploads/img/logo/' . $siteCfg['logo']    : 'assets/media/logos/logo-dark.png';
$hrmsFavicon = !empty($siteCfg['favicon']) ? HRMS_BASE . '/uploads/img/logo/' . $siteCfg['favicon'] : 'assets/media/logos/favicon.ico';

$fullName = trim(($profile['name'] ?? '') . ' ' . ($profile['middle_name'] ?? '') . ' ' . ($profile['last_name'] ?? ''));
$userInitials = '';
$parts = array_filter(explode(' ', $fullName));
if (count($parts) >= 2) { $userInitials = strtoupper(mb_substr(reset($parts), 0, 1) . mb_substr(end($parts), 0, 1)); }
else { $userInitials = strtoupper(mb_substr($fullName ?: 'U', 0, 2)); }

// Helper: build HRMS menu URL — routes through hrms_redirect.php for SSO session sync
function hrmsMenuUrl($item) {
    $url = '';
    if (!empty($item['external_link'])) {
        $url = $item['external_link'];
    } elseif (!empty($item['url']) && $item['url'] !== '#') {
        $url = HRMS_BASE . '/' . ltrim($item['url'], '/');
    }
    if (empty($url)) return 'javascript:;';
    return 'hrms_redirect.php?to=' . urlencode($url);
}

// Helper: build raw HRMS redirect URL for header links
function hrmsRedirectUrl($path = '') {
    $url = HRMS_BASE . ($path ? '/' . ltrim($path, '/') : '');
    return 'hrms_redirect.php?to=' . urlencode($url);
}

// Render menu icon: file icon → inline SVG → default fallback
function menuIcon($item) {
    if (!empty($item['svgi_icon_file'])) {
        return '<img src="' . e(HRMS_BASE . '/uploads/icons/' . $item['svgi_icon_file']) . '" alt="" style="width:22px;height:22px;opacity:.6;" />';
    }
    if (!empty($item['svgi_icon_svg'])) {
        return $item['svgi_icon_svg'];
    }
    return '<svg xmlns="http://www.w3.org/2000/svg" width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="#a5a4b5" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="1"/><circle cx="12" cy="5" r="1"/><circle cx="12" cy="19" r="1"/></svg>';
}
