    <!-- sub nav scroll -->
    <script>
      $(document).ready(function() {
        const $wrapper = $('.submenu-v2-wrapper');
        const $ul = $wrapper.find('ul.submenu-v2');
        const $prev = $wrapper.find('#scroll-subnav-prev');
        const $next = $wrapper.find('#scroll-subnav-next');

        function getMaxScrollLeft() {
          const el = $ul.get(0);
// total scrollable width - visible width
          return el.scrollWidth - el.clientWidth;
        }

        function updateTabs() {
          const parentWidth = $wrapper.width();
          const ulScrollWidth = $ul.get(0).scrollWidth;
          if (ulScrollWidth > parentWidth) {
// Show arrow buttons
            $prev.show();
            $next.show();
// Apply max-width and margin auto
            $ul.css({
              "max-width": "calc(100% - 85px)",
              "margin": "0 auto",
"overflow-x": "auto" // make sure scrollbar exists (even if hidden by your no-scrollbar class)
});
          } else {
// Hide arrows
            $prev.hide();
            $next.hide();
// Reset styling
            $ul.css({
              "max-width": "100%",
              "margin": "0",
              "overflow-x": "visible"
            });
          }
          updateButtonState();
        }

        function updateButtonState() {
          const el = $ul.get(0);
          const scrollLeft = el.scrollLeft;
          const maxScrollLeft = getMaxScrollLeft();
// Left edge
          if (scrollLeft <= 0) {
            $prev.addClass('disabled');
          } else {
            $prev.removeClass('disabled');
          }
        // Right edge
        if (scrollLeft >= maxScrollLeft - 1) { // small tolerance
          $next.addClass('disabled');
        } else {
          $next.removeClass('disabled');
        }
      }
      // Scroll left
      $prev.on('click', function() {
        if ($(this).hasClass('disabled')) return;
        const el = $ul.get(0);
        const current = el.scrollLeft;
        const newScroll = Math.max(0, current - 150);
        $ul.stop().animate({
          scrollLeft: newScroll
        }, 250, updateButtonState);
      });
      // Scroll right
      $next.on('click', function() {
        if ($(this).hasClass('disabled')) return;
        const el = $ul.get(0);
        const current = el.scrollLeft;
        const maxScrollLeft = getMaxScrollLeft();
        const newScroll = Math.min(maxScrollLeft, current + 150);
        $ul.stop().animate({
          scrollLeft: newScroll
        }, 250, updateButtonState);
      });
      // Update state on manual scroll (mouse / touch drag)
      $ul.on('scroll', function() {
        updateButtonState();
      });
      // Update on resize
      $(window).on('resize', updateTabs);
      // Initial check
      updateTabs();
      // scroll to center
      document.querySelectorAll('.submenu-v2-wrapper .nav').forEach(nav => {

    function centerItem(item) {
      if (!item) return;

      const navRect = nav.getBoundingClientRect();
      const itemRect = item.getBoundingClientRect();
      const currentScroll = nav.scrollLeft;

      const itemCenter =
        itemRect.left - navRect.left +
        currentScroll -
        (navRect.width / 2) +
        (itemRect.width / 2);

      nav.scrollTo({
        left: itemCenter,
        behavior: 'smooth'
      });
    }

    /* 🔹 On Click */
    nav.addEventListener('click', (e) => {
      const item = e.target.closest('.nav-item');
      if (!item) return;

      nav.querySelectorAll('.nav-item')
        .forEach(i => i.classList.remove('active'));

      item.classList.add('active');
      centerItem(item);
    });

    /* 🔹 On Page Load (Center Active) */
    const activeItem = nav.querySelector('.nav-item .nav-link.active');
    if (activeItem) {
      // small delay ensures layout is fully rendered
      setTimeout(() => {
        centerItem(activeItem);
      }, 50);
    }

  });
    });
  </script>
  <script>
    document.addEventListener("DOMContentLoaded", () => {
      let activeOffcanvas = null;

/* ---------- OPEN OFFCANVAS ---------- */
      document.addEventListener("click", (e) => {
        const trigger = e.target.closest(".offcanvas-trigger");
        if (!trigger) return;

        e.preventDefault();

        const selector = trigger.dataset.offcanvas;
        const offcanvas = document.querySelector(selector);
        if (!offcanvas) return;

        closeOffcanvas(); // close any open one

        offcanvas.classList.add("offcanvas-on");
        document.body.setAttribute("data-offcanvas-offcanvas", "on");
        document.body.classList.add("modal-open");

        // add overlay only once
        if (!document.querySelector(".offcanvas-overlay")) {
          const overlay = document.createElement("div");
          overlay.className = "offcanvas-overlay";
          offcanvas.insertAdjacentElement("afterend", overlay);
        }

        activeOffcanvas = offcanvas;

        // Pre-fill forms when their offcanvas opens
        if (selector === '#oC_basic-info' && typeof prefillBasicInfoForm === 'function') {
          prefillBasicInfoForm(window._profileData || {}, window._epPersonalData || {});
        }
        if (selector === '#oC_health-info' && typeof prefillHealthForm === 'function') {
          prefillHealthForm(window._healthData || null);
        }
        if (selector === '#oC_contact-info' && typeof prefillContactForm === 'function') {
          prefillContactForm(window._profileData || {}, window._emergencyContacts || [], window._addresses || [], window._personalDetails || {});
        }
        if (selector === '#oC_family-details' && typeof prefillFamilyForm === 'function') {
          var titleEl = document.getElementById('family-form-title');
          if (!isEditMode() || window._editingRecord.type !== 'family') {
            prefillFamilyForm(null);
            if (titleEl) titleEl.textContent = 'Add Family Member';
          } else {
            if (titleEl) titleEl.textContent = 'Edit Family Details';
          }
        }
        if (selector === '#oC_add-language') {
          var langTitle = document.getElementById('language-form-title');
          if (!isEditMode() || window._editingRecord.type !== 'language') {
            clearEditMode();
            resetForm('oC_add-language');
            if (langTitle) langTitle.textContent = 'Add Language';
          }
        }
        if (selector === '#oC_hobbie-sports-talent') {
          var hobbyTitle = document.getElementById('hobby-form-title');
          if (!isEditMode() || window._editingRecord.type !== 'hobby') {
            clearEditMode();
            resetForm('oC_hobbie-sports-talent');
            if (hobbyTitle) hobbyTitle.textContent = 'Add Hobby / Sport / Talent';
          }
        }
        if (selector === '#oC_talent-education') {
          var eduTitle = document.getElementById('edu-form-title');
          // Only reset if NOT opened via edit button (edit sets _editingEducation)
          if (!window._editingEducation) {
            resetForm('oC_talent-education');
            document.getElementById('edu-form-id').value = '';
            if (eduTitle) eduTitle.textContent = 'Add Education';
            var degSel = $('#edu-form-degree');
            if (degSel.length) degSel.val('').trigger('change');
          }
          window._editingEducation = null;
        }
        if (selector === '#oC_continuing-education') {
          if (!window._editingCE) {
            resetForm('oC_continuing-education');
            document.getElementById('ce-form-id').value = '';
            document.getElementById('ce-form-title').textContent = 'Add Training / Course';
            $('#ceYear input').val('');
          }
          window._editingCE = null;
        }
        if (selector === '#oC_add-experience') {
          if (!window._editingExp) {
            resetForm('oC_add-experience');
            document.getElementById('exp-form-id').value = '';
            document.getElementById('exp-form-title').textContent = 'Add Experience';
            $('#yearFrom1 input').val('');
            $('#yearTo1 input').val('');
            $('#current_job_1').prop('checked', false).trigger('change');
            $('#exp-form-highlights').val('');
          }
          window._editingExp = null;
        }
        if (selector === '#oC_volunteer-activity') {
          var volTitle = document.getElementById('volunteer-form-title');
          if (!isEditMode() || window._editingRecord.type !== 'volunteer') {
            clearEditMode();
            resetForm('oC_volunteer-activity');
            if (volTitle) volTitle.textContent = 'Add Volunteer Activity';
          }
        }
        if (selector === '#oC_patent') {
          var patTitle = document.getElementById('patent-form-title');
          if (!isEditMode() || window._editingRecord.type !== 'patent') {
            clearEditMode();
            resetForm('oC_patent');
            if (patTitle) patTitle.textContent = 'Add Patent';
          }
        }
        if (selector === '#oC_appreciation') {
          var appTitle = document.getElementById('appreciation-form-title');
          if (!isEditMode() || window._editingRecord.type !== 'award') {
            clearEditMode();
            resetForm('oC_appreciation');
            if (appTitle) appTitle.textContent = 'Add Appreciation';
          }
        }
        if (selector === '#oC_job-title') {
          var jtTitle = document.getElementById('job-title-form-title');
          if (jtTitle) jtTitle.textContent = 'Edit Classification Details';
          // Pre-fill FLSA & EEO from CI4 data
          var ci4 = window._jobDataCi4 || {};
          var panel = document.getElementById('oC_job-title');
          if (panel) {
            var setF = function(name, val) { var el = panel.querySelector('[name="' + name + '"]'); if (el) el.value = val || ''; };
            setF('flsa_status', ci4.flsa_status || '');
            setF('eeo_category', ci4.eeo_category || '');
          }
        }
        if (selector === '#oC_physical_location') {
          var pl = window._physicalLocation || {};
          var plPanel = document.getElementById('oC_physical_location');
          if (plPanel) {
            var setP = function(name, val) { var el = plPanel.querySelector('[name="' + name + '"]'); if (el) el.value = val || ''; };
            setP('office_name', pl.office_name);
            setP('building', pl.building);
            setP('floor', pl.floor);
            setP('desk', pl.desk);
            setP('work_arrangement', pl.work_arrangement);
            setP('office_days', pl.office_days);
            setP('time_zone', pl.time_zone);
            setP('country', pl.country);
            setP('region', pl.region);
          }
        }
        if (selector === '#oC_reporting_manager') {
          var hrms = window._jobDataHrms || {};
          var ci4 = window._jobDataCi4 || {};
          var rmPanel = document.getElementById('oC_reporting_manager');
          if (rmPanel) {
            var setR = function(name, val) { var el = rmPanel.querySelector('[name="' + name + '"]'); if (el) el.value = val || ''; };
            setR('rm_direct_name', hrms.reporting_to);
            setR('rm_direct_email', hrms.reporting_manager_email);
            setR('rm_direct_id', hrms.reporting_manager_id ? ('EMP-' + hrms.reporting_manager_id) : '');
            setR('reporting_since', ci4.reporting_since);
            setR('rm_matrix_name', hrms.matrix_manager);
            setR('rm_matrix_email', hrms.matrix_manager_email);
            setR('matrix_relationship', ci4.matrix_relationship);
            setR('rm_reviewer_name', hrms.reviewer_manager);
            setR('rm_reviewer_email', hrms.reviewer_manager_email);
            // Direct reports from HRMS cached data
            var drData = window._directReports || {};
            setR('rm_direct_reports_count', (drData.count || 0).toString());
            setR('rm_team_size', (drData.count || 0).toString());
          }
        }
        if (selector === '#oC_work_classification') {
          var wc = window._workClassData || {};
          var ci4wc = window._workClassCi4 || {};
          var wcPanel = document.getElementById('oC_work_classification');
          if (wcPanel) {
            var setW = function(id, val) { var el = document.getElementById(id); if (el) el.value = val || '–'; };
            setW('wc-form-workforce-type', (wc.workforce_type_names || []).join(', '));
            setW('wc-form-role', wc.role_role_name);
            setW('wc-form-cluster', wc.workforce_cluster_label);
            setW('wc-form-class1', wc.classification1_label);
            setW('wc-form-class2', wc.classification2_label);
            setW('wc-form-class3', wc.classification3_label);
            setW('wc-form-travel', (wc.travel_display || '–') + (wc.travel_label && wc.travel_label !== '–' ? ' (' + wc.travel_label + ')' : ''));
            setW('wc-form-compensation', wc.compensation_display);
            setW('wc-form-pattern', wc.working_pattern_display);
            setW('wc-form-arrangements', (wc.contract_arrangements || []).join(', '));
            var budgetEl = document.getElementById('wc-form-budget');
            if (budgetEl) budgetEl.value = ci4wc.budget_authority || '';
            var signingEl = document.getElementById('wc-form-signing');
            if (signingEl) signingEl.value = ci4wc.signing_authority || '';
          }
        }
        if (selector === '#oC_org_structure') {
          var osData = window._orgStructData || {};
          var ci4os = window._orgStructCi4 || window._jobDataCi4 || {};
          var setO = function(id, val) { var el = document.getElementById(id); if (el) el.value = val || '–'; };
          // HRMS readonly
          setO('os-form-business-unit', osData.business_unit);
          setO('os-form-division', osData.division_name);
          setO('os-form-department', osData.department_name);
          setO('os-form-team', osData.team);
          setO('os-form-job-code', osData.jobd_cost_code);
          setO('os-form-legal-entity', osData.legal_entity);
          // CI4 editable
          var ccEl = document.getElementById('os-form-cost-centre');
          if (ccEl) ccEl.value = ci4os.cost_centre_name || '';
          var glEl = document.getElementById('os-form-gl-code');
          if (glEl) glEl.value = ci4os.gl_code || '';
        }

        // ── Working Conditions prefill ──
        if (selector === '#oC_working-condition') {
          var wc = window._workingCondData || {};
          var chk = document.getElementById('accommodation-required-check');
          if (chk) {
            chk.checked = (wc.accommodation_required == 1 || wc.accommodation_required === true);
            // Toggle accommodation type visibility
            var typeSection = document.getElementById('accommodation-type-selection');
            if (typeSection) typeSection.classList.toggle('d-none', !chk.checked);
          }
          var typeSelect = document.getElementById('wcond-form-type');
          if (typeSelect) {
            typeSelect.value = wc.accommodation_type || '';
            if (typeSelect.classList.contains('select2-hidden-accessible')) {
              $(typeSelect).val(wc.accommodation_type || '').trigger('change');
            }
          }
          var eqEl = document.getElementById('wcond-form-equipment');
          if (eqEl) eqEl.value = wc.special_equipment || '';
          var ergoEl = document.getElementById('wcond-form-ergo-date');
          if (ergoEl) ergoEl.value = wc.last_ergonomic_assessment || '';
          var notesEl = document.getElementById('wcond-form-notes');
          if (notesEl) notesEl.value = wc.notes || '';
        }
      });

      /* ---------- CLOSE OFFCANVAS ---------- */
            document.addEventListener("click", (e) => {
              if (
                e.target.closest(".offcanvas-close")
          // || e.target.classList.contains("offcanvas-overlay") // optional
                ) {
                e.preventDefault();
              closeOffcanvas();
            }
          });

      /* ---------- ESC KEY CLOSE (optional) ---------- */
            document.addEventListener("keydown", (e) => {
              if (e.key === "Escape") closeOffcanvas();
            });

      /* ---------- CLOSE FUNCTION ---------- */
            function closeOffcanvas() {
              // Use tracked panel or find any open offcanvas (e.g. opened via window.openOffcanvas)
              var panel = activeOffcanvas || document.querySelector('.offcanvas.offcanvas-on');
              if (!panel) return;

              panel.classList.remove("offcanvas-on");
              document.body.removeAttribute("data-offcanvas-offcanvas");
              document.body.classList.remove("modal-open");
              document.querySelector(".offcanvas-overlay")?.remove();

              // Reset edit mode and form title when closing language/hobby forms
              var panelId = panel.id;
              if (panelId === 'oC_add-language') {
                if (typeof clearEditMode === 'function') clearEditMode();
                var langTitle = document.getElementById('language-form-title');
                if (langTitle) langTitle.textContent = 'Add Language';
              }
              if (panelId === 'oC_hobbie-sports-talent') {
                if (typeof clearEditMode === 'function') clearEditMode();
                var hobbyTitle = document.getElementById('hobby-form-title');
                if (hobbyTitle) hobbyTitle.textContent = 'Add Hobby / Sport / Talent';
              }
              if (panelId === 'oC_appreciation') {
                if (typeof clearEditMode === 'function') clearEditMode();
                var appTitle = document.getElementById('appreciation-form-title');
                if (appTitle) appTitle.textContent = 'Add Appreciation';
              }
              if (panelId === 'oC_patent') {
                if (typeof clearEditMode === 'function') clearEditMode();
                var ptTitle = document.getElementById('patent-form-title');
                if (ptTitle) ptTitle.textContent = 'Add Patent';
              }
