              if (panelId === 'oC_add-training') {
                if (typeof clearEditMode === 'function') clearEditMode();
                var trTitle = document.getElementById('oC_add-training-title');
                if (trTitle) trTitle.textContent = 'Add Training';
              }
              if (panelId === 'oC_transfer') {
                if (typeof clearEditMode === 'function') clearEditMode();
                var tfTitle = document.getElementById('oC_transfer-title');
                if (tfTitle) tfTitle.textContent = 'Add Transfer';
              }
              if (panelId === 'oC_add-certificate') {
                if (typeof clearEditMode === 'function') clearEditMode();
                var certTitle = document.getElementById('oC_add-certificate-title');
                if (certTitle) certTitle.textContent = 'Add Certification';
              }
              if (panelId === 'oC_add-IDP-goal') {
                if (typeof clearEditMode === 'function') clearEditMode();
                var idpTitle = document.getElementById('idp-goal-form-title');
                if (idpTitle) idpTitle.textContent = 'Add IDP Goal';
              }
              if (panelId === 'oC_add-mentoring') {
                if (typeof clearEditMode === 'function') clearEditMode();
                var mentTitle = document.getElementById('mentoring-form-title');
                if (mentTitle) mentTitle.textContent = 'Add Mentoring Program';
              }
              if (panelId === 'oC_add-skills-gap') {
                if (typeof clearEditMode === 'function') clearEditMode();
                var sgTitle = document.getElementById('sgap-form-title');
                if (sgTitle) sgTitle.textContent = 'Add Skill Gap';
              }

              activeOffcanvas = null;
            }
          });
        </script>
        <script type="text/javascript" src="https://cdn.jsdelivr.net/npm/select2@4.1.0-rc.0/dist/js/select2.min.js"></script>
        <link rel="stylesheet" type="text/css" href="https://cdn.jsdelivr.net/npm/select2@4.1.0-rc.0/dist/css/select2.min.css">

        <script type="text/javascript">
          $('.select2').select2();



        // country filter
          $(document).ready(function() {
            const baseUrl = "assets/media/svg/flags/";

            $(".country-select2-3").select2({
                //allowClear: true,
                tags: false, // Enable custom tags (cancel option)
                tokenSeparators: [',', ' '], // Separate by commas or spaces
                closeOnSelect: false, // Keep the dropdown open after selection
                data: [
                  { id: 0, countryImg: '001-austria.svg', text: 'Austria', subText: "AU" },
                  { id: 1, countryImg: '010-india.svg', text: 'India', subText: "IND" }
                ],
                templateResult: countryFormat,
                templateSelection: countrySelFormat1,
              });

            function updateSelectedCount3() {
              if (!$(".country-select2-3").length) return;
              let selectedOptions = $(".country-select2-3").select2("data");
              if (!selectedOptions) return;
              let count = selectedOptions.length;

                //let displayText = count > 0 ? `${count} selected` : "Select Countries";
                //$(".country-select2-3").next(".select2-container").find(".select2-selection__rendered").html(displayText);
              $(".country-select2-3").next(".select2-container").find(".select2-selection__rendered .select2-selection__choice").remove();
              $(".country-select2-3").next(".select2-container").find(".select2-selection__rendered .select2-search__field").attr("placeholder", "Search countries");
            }

            function updateSelectedItems3() {
              if (!$(".country-select2-3").length) return;
              let selectedOptions = $(".country-select2-3").select2("data");
              if (!selectedOptions) return;
              let selectedContainer = $("#country-selected-items");

                selectedContainer.empty(); // Clear previous selections

                selectedOptions.forEach(option => {
                    // Add each selected item wrapped in a <span> with a flag and cancel option (X)
                  selectedContainer.append(
                    `<span class="label label-inline label-light border border-secondary px-2">
                            <img src="${baseUrl}${option.countryImg}" class="h-10 mr-1">
                            ${option.text} 
                            <button type="button" class="remove-option btn p-0 ml-1 line-height-0">
                                <i class="la la-times text-danger font-13"></i>
                            </button>
                  </span>`
                  );
                });

                // Attach event to remove button (X)
                selectedContainer.on("click", ".remove-option", function() {
                  let label = $(this).parent().text().trim();

                    // Find the option in the Select2 dropdown
                  let optionToRemove = $(".country-select2-3").find("option").filter(function() {
                    return $(this).text().trim() === label;
                  });

                  if (optionToRemove.length) {
                    let valueToRemove = optionToRemove.val();

                        // Get current values and remove the one matching
                    let currentValue = $(".country-select2-3").val() || [];
                    let updatedValue = currentValue.filter(val => val !== valueToRemove);

                        // Update Select2 and trigger change
                    $(".country-select2-3").val(updatedValue).trigger("change");

                        updateSelectedItems3(); // Update the display after removal
                        updateSelectedCount3(); // Update the count
                      }
                    });
              }

            // On change, update count and selected items
              $(".country-select2-3").on("change", function() {
                updateSelectedCount3();
                updateSelectedItems3();
              });

            // Initialize selected items and count on page load
              updateSelectedCount3();
              updateSelectedItems3();

              function countryFormat(user) {
                if (!user.id) {
                  return user.text;
                }

                var baseUrl = "assets/media/svg/flags/";
                var $countryOutput = $(
                  '<div class="TPA-item text-dark d-flex align-items-center"><span class="TPA-code position-relative">' + user.subText + '</span><span class="table-profile-img align-self-center ml-0 mr-1 round"><img src="' + baseUrl + '/' + user.countryImg + '" /></span><span class="align-self-center">' + user.text + '</span></div>'
                  );
                return $countryOutput;
                
              };
              function countrySelFormat1(user) {
                if (!user.id) {
                  return user.text;
                }

                var baseUrl = "assets/media/svg/flags/";
                var $countryOutput = $(
                  '<div class="TPA-item text-dark d-flex align-items-center"> '+ user.subText +' <span class="mx-1 opacity-30">|</span> <span class="table-profile-img align-self-center ml-0 mr-1 round"><img src="' + baseUrl + '/' + user.countryImg + '" /></span></div>'
                  );
                return $countryOutput;
                
              };
            });

        // country filter end
          </script>

