          <!-- toast -->
          <script>
            const toast = document.querySelector(".added-toast");
            const closeIcon = document.querySelector(".close1");
            const progress = document.querySelector(".progress1");

            let timer1, timer2;

        // OPEN TOAST (any trigger)
            document.addEventListener("click", (e) => {
              const trigger = e.target.closest(".added-toast-trigger");
              if (!trigger) return;

          // reset if already running
              clearTimeout(timer1);
              clearTimeout(timer2);

              toast.classList.add("show");
              progress.classList.add("active");

              timer1 = setTimeout(() => {
                toast.classList.remove("show");
              }, 5000);

              timer2 = setTimeout(() => {
                progress.classList.remove("active");
              }, 5300);
            });

        // CLOSE TOAST
            closeIcon.addEventListener("click", () => {
              toast.classList.remove("show");
              progress.classList.remove("active");

              clearTimeout(timer1);
              clearTimeout(timer2);
            });
          </script>

