          <script>
            document.addEventListener("DOMContentLoaded", function () {

              const ctx = document.getElementById('ratingHistoryChart');

              const ratings = [4.3, 4.2, 4.8, 4.5, 4.5];

              new Chart(ctx, {
                type: 'bar',
                data: {
                  labels: ['2020', '2021', '2022', '2023', '2024'],
                  datasets: [{
                    data: ratings,
                    backgroundColor: [
                      '#cfd6e3',
                      '#cfd6e3',
                  '#bfc8d9', // Highlight 2022
                  '#cfd6e3',
                  '#cfd6e3'
                ],
                borderRadius: 10,
                barThickness: 40
              }]
            },
            options: {
              responsive: true,
              maintainAspectRatio: false,
              layout: {
                padding: {
                  top: 60   // 🔥 Prevent clipping
                }
              },
              plugins: {
                legend: { display: false },
                tooltip: { enabled: false }
              },
              scales: {
                y: {
                  display: false,
                  min: 0,
                  max: 5
                },
                x: {
                  grid: { display: false },
                  ticks: {
                    font: { size: 14 }
                  }
                }
              },
              animation: {
                duration: 1000
              }
            },
            plugins: [{
              id: 'customLabels',
              afterDatasetsDraw(chart) {
                const { ctx } = chart;
                ctx.save();
                ctx.textAlign = "center";

                chart.getDatasetMeta(0).data.forEach((bar, index) => {
                  const value = ratings[index];

                  // Draw value text
                  ctx.font = "bold 14px Arial";
                  ctx.fillStyle = index === 2 ? "#2563eb" : "#2c3e50";

                  const valueY = Math.max(bar.y - 10, 20);
                  ctx.fillText(value, bar.x, valueY);

                  // Trophy for 2022
                  if (index === 2) {
                    ctx.font = "18px Arial";
                    const trophyY = Math.max(bar.y - 30, 10);
                    ctx.fillText("🏆", bar.x, trophyY);
                  }
                });

                ctx.restore();
              }
            }]
          });

            });
          </script>
