    // ════════════════════════════════════════════
    // 2. Save Experience (enhanced with validation + edit)
    // ════════════════════════════════════════════
    var btnSaveExp = document.getElementById('btn-save-experience');
    if (btnSaveExp) {
      btnSaveExp.addEventListener('click', async function(e) {
        e.preventDefault();

        var designation = document.getElementById('exp-form-designation');
        var company = document.getElementById('exp-form-company');
        var yearFromInput = document.querySelector('#yearFrom1 input');
        var yearToInput = document.querySelector('#yearTo1 input');
        var locationInput = document.getElementById('exp-form-location');
        var isCurrentChk = document.getElementById('current_job_1');
        var highlights = document.getElementById('exp-form-highlights');
        var expId = document.getElementById('exp-form-id');

        // ── Validation ──
        if (!designation || !designation.value.trim()) { showToast('Please enter job title', 'error'); return; }
        if (!company || !company.value.trim()) { showToast('Please enter company name', 'error'); return; }

        var fromVal = yearFromInput ? yearFromInput.value.trim() : '';
        if (!fromVal) { showToast('Please select start date', 'error'); return; }

        var isCurChecked = isCurrentChk && isCurrentChk.checked;
        var toVal = yearToInput ? yearToInput.value.trim() : '';
        if (!isCurChecked && !toVal) { showToast('Please select end date or mark as current job', 'error'); return; }

        // Parse "Mon, YYYY" → "YYYY-MM-DD" for backend
        function parseMonYr(str) {
          if (!str) return '';
          var mos = {'jan':'01','feb':'02','mar':'03','apr':'04','may':'05','jun':'06','jul':'07','aug':'08','sep':'09','oct':'10','nov':'11','dec':'12'};
          var parts = str.replace(',', '').trim().split(/\s+/);
          if (parts.length >= 2) {
            var moKey = parts[0].toLowerCase().substring(0, 3);
            var yr = parts[1] || parts[0];
            if (mos[moKey] && /^\d{4}$/.test(yr)) return yr + '-' + mos[moKey] + '-01';
          }
          return str;
        }
        var startDate = parseMonYr(fromVal);
        var endDate = isCurChecked ? null : parseMonYr(toVal);

        // Date validation
        if (startDate && endDate) {
          if (new Date(startDate) > new Date(endDate)) { showToast('Start date cannot be after end date', 'error'); return; }
        }

        // Duplicate check: same designation + same company (skip if editing same record)
        var editingId = (expId && expId.value) ? String(expId.value) : '';
        var existingExp = window._workExpData || [];
        var dup = existingExp.find(function(ex) {
          if (editingId && String(ex.experience_id) === editingId) return false;
          return (ex.designation || '').toLowerCase() === designation.value.trim().toLowerCase()
              && (ex.company_name || '').toLowerCase() === company.value.trim().toLowerCase();
        });
        if (dup) { showToast('This role at the same company already exists', 'error'); return; }

        // Build payload
        var payload = {
          emp_id: empId,
          designation: designation.value.trim(),
          company_name: company.value.trim(),
          start_date: startDate,
          end_date: endDate,
          location: locationInput ? locationInput.value.trim() : '',
          is_current: isCurChecked ? 1 : 0,
          description: highlights ? highlights.value.trim() : ''
        };
        if (editingId) payload.experience_id = parseInt(editingId);

        // Loading state
        var lblEl = document.getElementById('btn-save-exp-label');
        var ldrEl = document.getElementById('btn-save-exp-loader');
        if (lblEl) lblEl.classList.add('d-none');
        if (ldrEl) ldrEl.classList.remove('d-none');
        btnSaveExp.disabled = true;

        try {
          var resp;
          if (editingId) {
            resp = await ci4Api('PUT', '/hrms-data/work-experience/' + editingId, payload);
          } else {
            resp = await ci4Api('POST', '/hrms-data/work-experience', payload);
          }
          showToast('Experience saved successfully', 'success');
          closeOffcanvas('oC_add-experience');
          resetForm('oC_add-experience');
          document.getElementById('exp-form-id').value = '';
          window._loadedTabs['talent'] = false;
          loadTalentData(empId);
        } catch (err) { showToast('Error saving experience', 'error'); console.error(err); }
        finally {
          if (lblEl) lblEl.classList.remove('d-none');
          if (ldrEl) ldrEl.classList.add('d-none');
          btnSaveExp.disabled = false;
        }
      });
    }

