    // ════════════════════════════════════════════
    // 4. Save Certificate (with edit support)
    // ════════════════════════════════════════════
    var btnSaveCert = document.getElementById('btn-save-certificate');
    if (btnSaveCert) {
      btnSaveCert.addEventListener('click', async function(e) {
        e.preventDefault();
        var certName = document.getElementById('cert-name');
        var certStartDate = document.getElementById('cert-start-date');
        var certEndDate = document.getElementById('cert-end-date');
        var certGrade = document.getElementById('cert-grade');

        if (!certName || !certName.value.trim()) { showToast('Please enter certification name', 'error'); return; }

        function convertDateForSave(val) {
          if (!val) return '';
          val = val.trim();
          if (/^\d{4}-\d{2}-\d{2}$/.test(val)) return val;
          var m = val.match(/^(\w+)[,\s]+(\d{4})$/);
          if (m) {
            var months = {Jan:'01',Feb:'02',Mar:'03',Apr:'04',May:'05',Jun:'06',Jul:'07',Aug:'08',Sep:'09',Oct:'10',Nov:'11',Dec:'12'};
            return m[2] + '-' + (months[m[1]] || '01') + '-01';
          }
          return val;
        }

        var startVal = convertDateForSave(certStartDate ? certStartDate.value : '');
        var endVal = convertDateForSave(certEndDate ? certEndDate.value : '');
        var payload = {
          emp_id: empId,
          certificate_name: certName.value.trim(),
          start_date: startVal || null,
          end_date: endVal || null,
          grade: certGrade ? certGrade.value.trim() : '',
          cost: (function() { var c = document.getElementById('cert-cost'); return c && c.value.trim() ? c.value.trim().replace(/[^0-9.]/g, '') : ''; })()
        };

        // Edit mode: include certification_id
        if (isEditMode() && window._editingRecord.type === 'certification') {
          payload.certification_id = window._editingRecord.id;
        }

        try {
          var resp;
          var certEditId = (isEditMode() && window._editingRecord.type === 'certification') ? window._editingRecord.id : null;
          if (certEditId) {
            resp = await ci4Api('PUT', '/hrms-data/certifications/' + certEditId, payload);
          } else {
            resp = await ci4Api('POST', '/hrms-data/certifications', payload);
          }
          showToast('Certification saved successfully', 'success');
          closeOffcanvas('oC_add-certificate');
          resetForm('oC_add-certificate');
          clearEditMode();
          invalidateCache('jobOrg');
          window._loadedTabs['jobOrg'] = false;
          loadJobOrgData(empId);
        } catch (err) { showToast('Error saving certification', 'error'); console.error(err); }
      });
    }

    // ════════════════════════════════════════════
    // 5. Save Award (with validation + edit support)
    // ════════════════════════════════════════════
    var btnSaveAward = document.getElementById('btn-save-award');
    if (btnSaveAward) {
      btnSaveAward.addEventListener('click', async function(e) {
        e.preventDefault();
        var panel = document.getElementById('oC_appreciation');
        if (!panel) return;
        function getAVal(name) { var el = panel.querySelector('[name="' + name + '"]'); return el ? el.value.trim() : ''; }

        // Clear previous errors
        panel.querySelectorAll('.is-invalid').forEach(function(el) { el.classList.remove('is-invalid'); el.title = ''; });
        function markAwardError(name, msg) {
          var el = panel.querySelector('[name="' + name + '"]');
          if (el) { el.classList.add('is-invalid'); el.title = msg; el.addEventListener('input', function() { this.classList.remove('is-invalid'); this.title = ''; }, { once: true }); el.addEventListener('change', function() { this.classList.remove('is-invalid'); this.title = ''; }, { once: true }); }
        }

        var awardName = getAVal('award_name');
        var awardType = getAVal('award_type');
        var awardedBy = getAVal('awarded_by');
        var description = getAVal('description');
        var rewardAmount = getAVal('reward_amount');
        var rawDate = getAVal('award_date') || (panel.querySelector('#appreciationDate') ? panel.querySelector('#appreciationDate').value.trim() : '');
        var errors = [];

        if (!awardType) { errors.push('Type is required'); markAwardError('award_type', 'Required'); }
        if (!awardedBy) { errors.push('Received From is required'); markAwardError('awarded_by', 'Required'); }
        else if (awardedBy.length > 100) { errors.push('Received From is too long (max 100)'); markAwardError('awarded_by', 'Max 100 characters'); }
        if (!description) { errors.push('Description is required'); markAwardError('description', 'Required'); }
        else if (description.length > 500) { errors.push('Description is too long (max 500)'); markAwardError('description', 'Max 500 characters'); }
        if (!awardName) { errors.push('Award Title is required'); markAwardError('award_name', 'Required'); }
        else if (awardName.length > 150) { errors.push('Award Title is too long (max 150)'); markAwardError('award_name', 'Max 150 characters'); }
        if (rewardAmount && isNaN(parseFloat(rewardAmount))) { errors.push('Cash value must be a number'); markAwardError('reward_amount', 'Must be a number'); }
        // Validate & convert date: must be past or today, convert mm/dd/yyyy → YYYY-MM-DD for DB
        var awardDateDb = '';
        if (rawDate) {
          var parts = rawDate.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
          if (parts) {
            awardDateDb = parts[3] + '-' + parts[1].padStart(2, '0') + '-' + parts[2].padStart(2, '0');
          } else if (/^\d{4}-\d{2}-\d{2}$/.test(rawDate)) {
            awardDateDb = rawDate; // already YYYY-MM-DD
          } else {
            errors.push('Invalid date format'); markAwardError('award_date', 'Invalid date');
          }
          if (awardDateDb) {
            var d = new Date(awardDateDb + 'T00:00:00');
            var today = new Date(); today.setHours(0,0,0,0);
            if (isNaN(d.getTime())) { errors.push('Invalid date'); markAwardError('award_date', 'Invalid date'); }
            else if (d > today) { errors.push('Date cannot be in the future'); markAwardError('award_date', 'Must be past date'); }
          }
        }

        if (errors.length > 0) { showToast(errors[0], 'error'); var firstErr = panel.querySelector('.is-invalid'); if (firstErr) firstErr.focus(); return; }

        var payload = {
          emp_id: empId,
          award_name: awardName,
          award_type: awardType,
          awarded_by: awardedBy,
          description: description,
          award_date: awardDateDb,
          reward_amount: rewardAmount
        };

        // If editing, include the award_id
        if (isEditMode() && window._editingRecord.type === 'award') {
          payload.award_id = window._editingRecord.id;
        }

        try {
          var resp;
          var awardEditId = (isEditMode() && window._editingRecord.type === 'award') ? window._editingRecord.id : null;
          if (awardEditId) {
            resp = await ci4Api('PUT', '/hrms-data/awards/' + awardEditId, payload);
          } else {
            resp = await ci4Api('POST', '/hrms-data/awards', payload);
          }
          showToast('Award saved successfully', 'success');
          clearEditMode();
          closeOffcanvas('oC_appreciation');
          resetForm('oC_appreciation');
          var appTitle = document.getElementById('appreciation-form-title');
          if (appTitle) appTitle.textContent = 'Add Appreciation';
          invalidateCache('talent');
          loadTalentData(empId);
        } catch (err) { showToast('Error saving award', 'error'); console.error(err); }
      });
    }

    // ════════════════════════════════════════════
    // 6. Save Basic Info → CI4 /profile/personal-details (EP fields only)
    // ════════════════════════════════════════════
    var btnSaveBasic = document.getElementById('btn-save-basic-info');
    if (btnSaveBasic) {
      btnSaveBasic.addEventListener('click', async function(e) {
        e.preventDefault();
        var panel = document.getElementById('oC_basic-info');
        // Only EP-editable fields — HRMS fields are readonly
        function getVal(name) { var el = panel.querySelector('[name="' + name + '"]'); return el ? el.value.trim() : ''; }

        // ── Validation ──
        function markError(name, msg) {
          var el = panel.querySelector('[name="' + name + '"]');
          if (el) { el.classList.add('is-invalid'); el.setAttribute('title', msg); }
        }
        function clearErrors() {
          panel.querySelectorAll('.is-invalid').forEach(function(el) { el.classList.remove('is-invalid'); el.removeAttribute('title'); });
        }
        clearErrors();
        panel.querySelectorAll('input:not([readonly]), select, textarea').forEach(function(el) {
          el.addEventListener('input', function() { el.classList.remove('is-invalid'); el.removeAttribute('title'); }, { once: true });
          el.addEventListener('change', function() { el.classList.remove('is-invalid'); el.removeAttribute('title'); }, { once: true });
        });
        var nameRe = /^[A-Za-z\s.\-']+$/;
        var errors = [];

        // Preferred name — optional, letters only, max 100
        var preferredName = getVal('preferred_name');
        if (preferredName && preferredName.length > 100) { errors.push('Preferred name is too long (max 100)'); markError('preferred_name', 'Max 100 characters'); }
        else if (preferredName && !nameRe.test(preferredName)) { errors.push('Preferred name contains invalid characters'); markError('preferred_name', 'Letters, spaces, hyphens, dots only'); }

        // Name arabic — optional, max 255
        var nameArabic = getVal('name_arabic');
        if (nameArabic && nameArabic.length > 255) { errors.push('Arabic name is too long (max 255)'); markError('name_arabic', 'Max 255 characters'); }

        // Birth details — optional, max 100 each
        var countryBirth = getVal('country_of_birth');
        if (countryBirth && countryBirth.length > 100) { errors.push('Country of birth is too long'); markError('country_of_birth', 'Max 100 characters'); }
        var stateBirth = getVal('state_of_birth');
        if (stateBirth && stateBirth.length > 100) { errors.push('State of birth is too long'); markError('state_of_birth', 'Max 100 characters'); }
        var cityBirth = getVal('city_of_birth');
        if (cityBirth && cityBirth.length > 100) { errors.push('City of birth is too long'); markError('city_of_birth', 'Max 100 characters'); }

        // Spouse name — optional, letters only, max 255
        var spouseName = getVal('spouse_name');
        if (spouseName && spouseName.length > 255) { errors.push('Spouse name is too long'); markError('spouse_name', 'Max 255 characters'); }
        else if (spouseName && !nameRe.test(spouseName)) { errors.push('Spouse name contains invalid characters'); markError('spouse_name', 'Letters, spaces, hyphens, dots only'); }

        // Marriage date — optional, must be valid date, not in the future
        var marriageDate = getVal('marriage_date');
        if (marriageDate) {
          var md = new Date(marriageDate);
          if (isNaN(md.getTime())) { errors.push('Marriage date is invalid'); markError('marriage_date', 'Invalid date'); }
          else if (md > new Date()) { errors.push('Marriage date cannot be in the future'); markError('marriage_date', 'Cannot be future date'); }
        }

        // Passport expiry — optional, must be valid date
        var passportExpiry = getVal('passport_expiry');
        if (passportExpiry) {
          var pe = new Date(passportExpiry);
          if (isNaN(pe.getTime())) { errors.push('Passport expiry is invalid'); markError('passport_expiry', 'Invalid date'); }
        }

        // Denomination — optional, max 100
        var denomination = getVal('denomination');
        if (denomination && denomination.length > 100) { errors.push('Denomination is too long'); markError('denomination', 'Max 100 characters'); }

        if (errors.length > 0) {
          showToast(errors[0], 'error');
          var firstInvalid = panel.querySelector('.is-invalid');
          if (firstInvalid) firstInvalid.focus();
          return;
        }

        var payload = {
          preferred_name:    preferredName,
          name_arabic:       nameArabic,
          pronouns:          getVal('pronouns'),
          country_of_birth:  countryBirth,
          state_of_birth:    stateBirth,
          city_of_birth:     cityBirth,
          citizenship_type:  getVal('citizenship_type'),
          spouse_name:       spouseName,
          marriage_date:     marriageDate,
          denomination:      denomination,
          passport_expiry:   passportExpiry,
          blood_group:       getVal('blood_group')
        };
        try {
          var resp = await ci4Api('PUT', '/profile/personal-details', payload);
          showToast('Basic info updated successfully', 'success');
          closeOffcanvas('oC_basic-info');
          // Live update: re-fetch and re-render personal profile data + hero
          invalidateCache('personal');
          loadPersonalProfile(empId);
          loadProfile(empId);
          // Also update the stored EP data for future prefills
          if (resp && resp.data) window._epPersonalData = resp.data;
        } catch (err) { showToast(err.message || 'Error updating basic info', 'error'); console.error(err); }
      });
    }

    // ════════════════════════════════════════════
    // 7. Save Contact Info (HRMS + CI4 backend) — live update
    // ════════════════════════════════════════════
    var btnSaveContact = document.getElementById('btn-save-contact-info');
    if (btnSaveContact) {
      btnSaveContact.addEventListener('click', async function(e) {
        e.preventDefault();
        var panel = document.getElementById('oC_contact-info');
        if (!panel) return;
        function getVal(name) { var el = panel.querySelector('[name="' + name + '"]'); return el ? el.value.trim() : ''; }

        // ── Validation helpers ──
        function markError(name, msg) {
          var el = panel.querySelector('[name="' + name + '"]');
          if (el) { el.classList.add('is-invalid'); el.setAttribute('title', msg); }
        }
        function clearErrors() {
          panel.querySelectorAll('.is-invalid').forEach(function(el) { el.classList.remove('is-invalid'); el.removeAttribute('title'); });
        }
        var phoneRe = /^[\+]?[\d\s\-\(\)]{7,20}$/;
        var emailRe = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
        var urlRe = /^https?:\/\/.+/;
        var postalRe = /^[A-Za-z0-9\s\-]{3,10}$/;

        clearErrors();
        // Clear error on individual field when user types
        panel.querySelectorAll('input, select, textarea').forEach(function(el) {
          el.addEventListener('input', function() { el.classList.remove('is-invalid'); el.removeAttribute('title'); }, { once: true });
        });
        var errors = [];

        // Required: Mobile
        var mobile = getVal('contact');
        if (!mobile) { errors.push('Mobile number is required'); markError('contact', 'Required'); }
        else if (!phoneRe.test(mobile)) { errors.push('Mobile number is invalid'); markError('contact', 'Invalid phone number'); }

        // Optional phone fields — validate format only if filled
        var workPhone = getVal('work_phone');
        if (workPhone && !phoneRe.test(workPhone)) { errors.push('Work phone is invalid'); markError('work_phone', 'Invalid phone number'); }

        var workExt = getVal('work_extension');
        if (workExt && !/^\d{1,10}$/.test(workExt)) { errors.push('Extension must be digits only'); markError('work_extension', 'Digits only'); }

        // Email validation
        var altEmail = getVal('alternate_contact');
        if (altEmail && !emailRe.test(altEmail)) { errors.push('Personal email is invalid'); markError('alternate_contact', 'Invalid email'); }

        // Emergency contact — if any field filled, name + phone are required
        var ecName = getVal('emergency_name');
        var ecPhone = getVal('emergency_phone');
        var ecRelationship = getVal('emergency_relationship');
        if (ecName || ecPhone || ecRelationship) {
          if (!ecName) { errors.push('Emergency contact name is required'); markError('emergency_name', 'Required'); }
          if (!ecPhone) { errors.push('Emergency contact phone is required'); markError('emergency_phone', 'Required'); }
          else if (!phoneRe.test(ecPhone)) { errors.push('Emergency phone is invalid'); markError('emergency_phone', 'Invalid phone number'); }
        }

        // Address — if street filled, city is required
        var permStreet = getVal('perm_street');
        var permCity = getVal('perm_city');
        if (permStreet && !permCity) { errors.push('Permanent address city is required'); markError('perm_city', 'Required with address'); }
        var permZip = getVal('perm_postal_code');
        if (permZip && !postalRe.test(permZip)) { errors.push('Permanent postal code is invalid'); markError('perm_postal_code', 'Invalid'); }

        var currStreet = getVal('curr_street');
        var currCity = getVal('curr_city');
        if (currStreet && !currCity) { errors.push('Current address city is required'); markError('curr_city', 'Required with address'); }
        var currZip = getVal('curr_postal_code');
        if (currZip && !postalRe.test(currZip)) { errors.push('Current postal code is invalid'); markError('curr_postal_code', 'Invalid'); }

        // Social URLs — validate format only if filled
        ['linkedin_url', 'github_url', 'website_url', 'twitter_url'].forEach(function(field) {
          var v = getVal(field);
          if (v && !urlRe.test(v)) { errors.push(field.replace('_url', '').replace('_', ' ') + ' URL must start with http:// or https://'); markError(field, 'Must start with http:// or https://'); }
        });

        if (errors.length > 0) {
          showToast(errors[0], 'error');
          // Focus first invalid field
          var firstInvalid = panel.querySelector('.is-invalid');
          if (firstInvalid) firstInvalid.focus();
          return;
        }

        try {
          // 1) Save basic contact via CI4 proxy
          var contactPayload = {
            contact: mobile,
            email: getVal('email'),
            alternate_contact: getVal('alternate_contact')
          };
          await ci4Api('PUT', '/hrms-data/contact', contactPayload);

          // 2) Save emergency contact to CI4
          var ecResult = null;
          if (ecName && ecPhone) {
            var ecPayload = { contact_name: ecName, phone_number: ecPhone, relationship: ecRelationship, is_primary: 1 };
            var existing = window._emergencyContacts || [];
            if (existing.length > 0) {
              ecResult = await ci4Api('PUT', '/profile/emergency-contacts/' + existing[0].id, ecPayload);
            } else {
              ecResult = await ci4Api('POST', '/profile/emergency-contacts', ecPayload);
            }
          }

          // 3) Save addresses to CI4
          var existingAddresses = window._addresses || [];
          var permAddr = existingAddresses.find(function(a) { return a.address_type === 'Permanent'; });
          var currAddr = existingAddresses.find(function(a) { return a.address_type === 'Residential' || a.address_type === 'Current'; });
          var permResult = null;
          if (permStreet) {
            var permPayload = { address_type: 'Permanent', street_address: permStreet, state: getVal('perm_state'), city: getVal('perm_city'), postal_code: getVal('perm_postal_code'), country: 'India' };
            if (permAddr) { permResult = await ci4Api('PUT', '/profile/addresses/' + permAddr.id, permPayload); }
            else { permResult = await ci4Api('POST', '/profile/addresses', permPayload); }
          }
          var currResult = null;
          if (currStreet) {
            var currPayload = { address_type: 'Residential', street_address: currStreet, state: getVal('curr_state'), city: getVal('curr_city'), postal_code: getVal('curr_postal_code'), country: 'India' };
            if (currAddr) { currResult = await ci4Api('PUT', '/profile/addresses/' + currAddr.id, currPayload); }
            else { currResult = await ci4Api('POST', '/profile/addresses', currPayload); }
          }

          // 4) Save social profiles to CI4 personal details
          var socialPayload = { linkedin_url: getVal('linkedin_url'), github_url: getVal('github_url'), website_url: getVal('website_url'), twitter_url: getVal('twitter_url'), work_phone: getVal('work_phone'), work_extension: getVal('work_extension') };
          await ci4Api('PUT', '/profile/personal-details', socialPayload);

          // ── Live update: update cached data from form values ──
          // Update profile data
          if (window._profileData) {
            window._profileData.contact = mobile;
            window._profileData.email = getVal('email');
            window._profileData.alternate_contact = getVal('alternate_contact');
            window._profileData.work_phone = getVal('work_phone');
            window._profileData.work_extension = getVal('work_extension');
          }

          // Update emergency contacts cache
          var ecObj = { contact_name: ecName, phone_number: ecPhone, relationship: ecRelationship };
          if (window._emergencyContacts && window._emergencyContacts.length > 0) {
            ecObj.id = window._emergencyContacts[0].id;
            window._emergencyContacts[0] = ecObj;
          } else if (ecResult && ecResult.data && ecResult.data.id) {
            ecObj.id = ecResult.data.id;
            window._emergencyContacts = [ecObj];
          } else if (ecName && ecPhone) {
            window._emergencyContacts = [ecObj];
          }

          // Update addresses cache
          var updatedAddresses = (window._addresses || []).slice();
          var pIdx = updatedAddresses.findIndex(function(a) { return a.address_type === 'Permanent'; });
          if (permStreet) {
            var pObj = { address_type: 'Permanent', street_address: permStreet, state: getVal('perm_state'), city: getVal('perm_city'), postal_code: getVal('perm_postal_code') };
            if (pIdx !== -1) { pObj.id = updatedAddresses[pIdx].id; updatedAddresses[pIdx] = pObj; }
            else {
              if (permResult && permResult.data && permResult.data.id) pObj.id = permResult.data.id;
              updatedAddresses.push(pObj);
            }
          }
          var cIdx = updatedAddresses.findIndex(function(a) { return a.address_type === 'Residential' || a.address_type === 'Current'; });
          if (currStreet) {
            var cObj = { address_type: 'Residential', street_address: currStreet, state: getVal('curr_state'), city: getVal('curr_city'), postal_code: getVal('curr_postal_code') };
            if (cIdx !== -1) { cObj.id = updatedAddresses[cIdx].id; updatedAddresses[cIdx] = cObj; }
            else {
              if (currResult && currResult.data && currResult.data.id) cObj.id = currResult.data.id;
              updatedAddresses.push(cObj);
            }
          }
          window._addresses = updatedAddresses;

          // Update personal details cache (social)
          window._personalDetails = window._personalDetails || {};
          window._personalDetails.linkedin_url = getVal('linkedin_url');
          window._personalDetails.github_url = getVal('github_url');
          window._personalDetails.website_url = getVal('website_url');
          window._personalDetails.twitter_url = getVal('twitter_url');
          window._personalDetails.work_phone = getVal('work_phone');
          window._personalDetails.work_extension = getVal('work_extension');

          // Re-render Contact & Social display live (no reload)
          populateContactDisplay(window._profileData, window._emergencyContacts, window._addresses, window._personalDetails);

          // Update banner contact info
          setTextById('contact-email', getVal('email') || '–');
          setTextById('contact-phone', mobile || '–');

          showToast('Contact info updated successfully', 'success');
          closeOffcanvas('oC_contact-info');
        } catch (err) { showToast(err.message || 'Error updating contact info', 'error'); console.error(err); }
      });
    }

    // ════════════════════════════════════════════
    // 8. Save Health Info (CI4 backend)
    // ════════════════════════════════════════════
    var btnSaveHealth = document.getElementById('btn-save-health-info');
    if (btnSaveHealth) {
      btnSaveHealth.addEventListener('click', async function(e) {
        e.preventDefault();
        var panel = document.getElementById('oC_health-info');
        function getVal(name) { var el = panel.querySelector('[name="' + name + '"]'); return el ? el.value : ''; }
        function getChecked(name) { var el = panel.querySelector('[name="' + name + '"]'); return el && el.checked ? 1 : 0; }
        // ── Validation ──
        function markError(name, msg) {
          var el = panel.querySelector('[name="' + name + '"]');
          if (el) { el.classList.add('is-invalid'); el.setAttribute('title', msg); }
        }
        function clearErrors() {
          panel.querySelectorAll('.is-invalid').forEach(function(el) { el.classList.remove('is-invalid'); el.removeAttribute('title'); });
        }
        clearErrors();
        panel.querySelectorAll('input, select, textarea').forEach(function(el) {
          el.addEventListener('input', function() { el.classList.remove('is-invalid'); el.removeAttribute('title'); }, { once: true });
          el.addEventListener('change', function() { el.classList.remove('is-invalid'); el.removeAttribute('title'); }, { once: true });
        });
        var errors = [];

        // Blood group — required
        var bloodGroup = getVal('blood_group');
        if (!bloodGroup) { errors.push('Blood group is required'); markError('blood_group', 'Required'); }

        // Height — optional, must be 0-300
        var height = getVal('height');
        if (height) {
          var h = parseFloat(height);
          if (isNaN(h) || h < 0 || h > 300) { errors.push('Height must be 0–300 cm'); markError('height', '0–300 cm'); }
        }

        // Weight — optional, must be 0-500
        var weight = getVal('weight');
        if (weight) {
          var w = parseFloat(weight);
          if (isNaN(w) || w < 0 || w > 500) { errors.push('Weight must be 0–500 kg'); markError('weight', '0–500 kg'); }
        }

        // Last medical checkup — optional, must not be in the future
        var checkupDate = getVal('last_medical_checkup_date');
        if (checkupDate) {
          var cd = new Date(checkupDate);
          if (isNaN(cd.getTime())) { errors.push('Invalid checkup date'); markError('last_medical_checkup_date', 'Invalid date'); }
          else if (cd > new Date()) { errors.push('Checkup date cannot be in the future'); markError('last_medical_checkup_date', 'Cannot be future date'); }
        }

        // Textareas — max length
        var allergies = getVal('allergies');
        if (allergies && allergies.length > 1000) { errors.push('Allergies text is too long (max 1000)'); markError('allergies', 'Max 1000 characters'); }
        var chronic = getVal('chronic_conditions');
        if (chronic && chronic.length > 1000) { errors.push('Chronic conditions text is too long (max 1000)'); markError('chronic_conditions', 'Max 1000 characters'); }
        var marks = getVal('identification_marks');
        if (marks && marks.length > 500) { errors.push('Identification marks text is too long (max 500)'); markError('identification_marks', 'Max 500 characters'); }

        if (errors.length > 0) {
          showToast(errors[0], 'error');
          var firstInvalid = panel.querySelector('.is-invalid');
          if (firstInvalid) firstInvalid.focus();
          return;
        }

        var payload = {
          blood_group: bloodGroup,
          height: height,
          weight: weight,
          is_blood_donor: getChecked('is_blood_donor'),
          last_medical_checkup_date: checkupDate,
          vision_status: getVal('vision_status'),
          correction_type: getVal('correction_type'),
          color_blindness: getVal('color_blindness'),
          allergies: allergies,
          chronic_conditions: chronic,
          physical_disability: getVal('physical_disability'),
          identification_marks: marks
        };
        try {
          var resp = await ci4Api('PUT', '/profile/health', payload);
          showToast('Health records updated', 'success');
          closeOffcanvas('oC_health-info');
          // Live update display without full reload
          var updatedData = (resp && resp.data) ? resp.data : payload;
          window._healthData = updatedData;
          populateHealthDisplay(updatedData);
          // Also update Tab 2 health display
          invalidateCache('identity');
        } catch (err) { showToast(err.message || 'Save failed', 'error'); }
      });
    }

    // ════════════════════════════════════════════
    // 9. Save Family Details (CI4 backend)
    // ════════════════════════════════════════════
    (function() {
      var btnSaveFamily = document.getElementById('btn-save-family');
      if (!btnSaveFamily) return;
      btnSaveFamily.addEventListener('click', async function(e) {
        e.preventDefault();
        var panel = document.getElementById('oC_family-details');
        if (!panel) return;
        function getVal(name) { var el = panel.querySelector('[name="' + name + '"]'); return el ? el.value : ''; }
        function getChecked(name) { var el = panel.querySelector('[name="' + name + '"]'); return el && el.checked ? 1 : 0; }

        // ── Validation ──
        function markError(name, msg) {
          var el = panel.querySelector('[name="' + name + '"]');
          if (el) { el.classList.add('is-invalid'); el.setAttribute('title', msg); }
        }
        function clearErrors() {
          panel.querySelectorAll('.is-invalid').forEach(function(el) { el.classList.remove('is-invalid'); el.removeAttribute('title'); });
        }
        clearErrors();
        panel.querySelectorAll('input, select').forEach(function(el) {
          el.addEventListener('input', function() { el.classList.remove('is-invalid'); el.removeAttribute('title'); }, { once: true });
          el.addEventListener('change', function() { el.classList.remove('is-invalid'); el.removeAttribute('title'); }, { once: true });
        });

        var phoneRe = /^[\+]?[\d\s\-\(\)]{7,20}$/;
        var errors = [];

        var nameVal = getVal('name').trim();
        var relationship = getVal('relationship');

        // Required fields
        if (!nameVal) { errors.push('Full name is required'); markError('name', 'Required'); }
        else if (nameVal.length > 255) { errors.push('Name is too long (max 255 chars)'); markError('name', 'Max 255 characters'); }
        else if (!/^[A-Za-z\s.\-']+$/.test(nameVal)) { errors.push('Name contains invalid characters'); markError('name', 'Letters, spaces, hyphens, dots only'); }

        if (!relationship) { errors.push('Relationship is required'); markError('relationship', 'Required'); }

        // Date of birth — optional, but must be valid and not in the future
        var dob = getVal('date_of_birth');
        if (dob) {
          var dobDate = new Date(dob);
          if (isNaN(dobDate.getTime())) { errors.push('Date of birth is invalid'); markError('date_of_birth', 'Invalid date'); }
          else if (dobDate > new Date()) { errors.push('Date of birth cannot be in the future'); markError('date_of_birth', 'Cannot be future date'); }
        }

        // Contact number — optional, validate format if filled
        var contactNum = getVal('contact_number').trim();
        if (contactNum && !phoneRe.test(contactNum)) { errors.push('Contact number is invalid'); markError('contact_number', 'Invalid phone number'); }

        // Occupation — optional, max 255
        var occupation = getVal('occupation').trim();
        if (occupation && occupation.length > 255) { errors.push('Occupation is too long'); markError('occupation', 'Max 255 characters'); }

        if (errors.length > 0) {
          showToast(errors[0], 'error');
          var firstInvalid = panel.querySelector('.is-invalid');
          if (firstInvalid) firstInvalid.focus();
          return;
        }

        var payload = {
          name: nameVal,
          relationship: relationship,
          date_of_birth: dob,
          gender: getVal('gender'),
          occupation: occupation,
          education_level: getVal('education_level'),
          contact_number: contactNum,
          dependent_for_insurance: getChecked('dependent_for_insurance')
        };
        try {
          if (isEditMode() && _editingRecord.type === 'family') {
            await ci4Api('PUT', '/profile/family-dependents/' + _editingRecord.id, payload);
            clearEditMode();
          } else {
            await ci4Api('POST', '/profile/family-dependents', payload);
          }
          showToast('Family member saved', 'success');
          closeOffcanvas('oC_family-details');
          resetForm('oC_family-details');
          // Live refresh family display
          invalidateCache('personal');
          try {
            var familyRes = await ci4Api('GET', '/profile/family-dependents').catch(function() { return { data: [] }; });
            var family = (familyRes && familyRes.data) || [];
            window._familyData = family;
            populateFamilyDisplay(family);
          } catch(e) { /* fallback: full reload */ loadPersonalProfile(empId); }
        } catch (err) { showToast(err.message || 'Save failed', 'error'); }
      });
    })();

    // ════════════════════════════════════════════
    // 10. Save Language (CI4 backend)
    // ════════════════════════════════════════════
    var btnSaveLang = document.getElementById('btn-save-language');
    if (btnSaveLang) {
      btnSaveLang.addEventListener('click', async function(e) {
        e.preventDefault();
        var panel = document.getElementById('oC_add-language');
        if (!panel) return;
        function getVal(name) { var el = panel.querySelector('[name="' + name + '"]'); return el ? el.value : ''; }
        function getChecked(name) { var el = panel.querySelector('[name="' + name + '"]'); return el && el.checked ? 1 : 0; }

        // Clear previous errors
        panel.querySelectorAll('.is-invalid').forEach(function(el) { el.classList.remove('is-invalid'); el.title = ''; });

        function markLangError(name, msg) {
          var el = panel.querySelector('[name="' + name + '"]');
          if (el) { el.classList.add('is-invalid'); el.title = msg; el.addEventListener('input', function() { this.classList.remove('is-invalid'); this.title = ''; }, { once: true }); el.addEventListener('change', function() { this.classList.remove('is-invalid'); this.title = ''; }, { once: true }); }
        }

        var lang = getVal('language').trim();
        var proficiency = getVal('proficiency');
        var errors = [];
        var langNameRe = /^[A-Za-z\s.\-'()]+$/;

        if (!lang) { errors.push('Language is required'); markLangError('language', 'Required'); }
        else if (lang.length > 100) { errors.push('Language name is too long (max 100)'); markLangError('language', 'Max 100 characters'); }
        else if (!langNameRe.test(lang)) { errors.push('Language name contains invalid characters'); markLangError('language', 'Letters and spaces only'); }

        if (!proficiency) { errors.push('Proficiency is required'); markLangError('proficiency', 'Required'); }
        else if (['Native', 'Fluent', 'Intermediate', 'Basic'].indexOf(proficiency) === -1) { errors.push('Invalid proficiency level'); markLangError('proficiency', 'Select a valid level'); }

        // Check for duplicate language
        if (lang && window._langData) {
          var editId = (isEditMode() && window._editingRecord.type === 'language') ? Number(window._editingRecord.id) : null;
          var duplicate = window._langData.find(function(l) { return l.language.toLowerCase() === lang.toLowerCase() && Number(l.id) !== editId; });
          if (duplicate) { errors.push('This language already exists'); markLangError('language', 'Already added'); }
        }

        if (errors.length > 0) { showToast(errors[0], 'error'); var firstErr = panel.querySelector('.is-invalid'); if (firstErr) firstErr.focus(); return; }

        var payload = {
          language: lang,
          proficiency: proficiency,
          can_read: getChecked('can_read'),
          can_write: getChecked('can_write'),
          can_speak: getChecked('can_speak')
        };
        try {
          if (isEditMode() && window._editingRecord.type === 'language') {
            await ci4Api('PUT', '/profile/languages/' + window._editingRecord.id, payload);
            clearEditMode();
          } else {
            await ci4Api('POST', '/profile/languages', payload);
          }
          showToast('Language saved', 'success');
          closeOffcanvas('oC_add-language');
          resetForm('oC_add-language');
          // Live refresh
          var refreshRes = await ci4Api('GET', '/profile/languages').catch(function() { return { data: [] }; });
          window._langData = (refreshRes && refreshRes.data) || [];
          populateLanguagesDisplay(window._langData);
        } catch (err) { showToast(err.message || 'Save failed', 'error'); }
      });
    }

    // ════════════════════════════════════════════
    // 11. Save Hobby/Sport/Talent (CI4 backend)
    // ════════════════════════════════════════════
    var btnSaveHobby = document.getElementById('btn-save-hobby');
    if (btnSaveHobby) {
      btnSaveHobby.addEventListener('click', async function(e) {
        e.preventDefault();
        var panel = document.getElementById('oC_hobbie-sports-talent');
        if (!panel) return;
        function getVal(name) { var el = panel.querySelector('[name="' + name + '"]'); return el ? el.value : ''; }

        // Clear previous errors
        panel.querySelectorAll('.is-invalid').forEach(function(el) { el.classList.remove('is-invalid'); el.title = ''; });

        function markHobbyError(name, msg) {
          var el = panel.querySelector('[name="' + name + '"]');
          if (el) { el.classList.add('is-invalid'); el.title = msg; el.addEventListener('input', function() { this.classList.remove('is-invalid'); this.title = ''; }, { once: true }); el.addEventListener('change', function() { this.classList.remove('is-invalid'); this.title = ''; }, { once: true }); }
        }

        var hobbyName = getVal('name').trim();
        var category = getVal('category');
        var errors = [];
        var nameRe = /^[A-Za-z0-9\s.\-'&,()]+$/;

        if (!hobbyName) { errors.push('Name is required'); markHobbyError('name', 'Required'); }
        else if (hobbyName.length > 100) { errors.push('Name is too long (max 100)'); markHobbyError('name', 'Max 100 characters'); }
        else if (!nameRe.test(hobbyName)) { errors.push('Name contains invalid characters'); markHobbyError('name', 'Letters, numbers, spaces, hyphens only'); }

        if (!category) { errors.push('Category is required'); markHobbyError('category', 'Required'); }
        else if (['hobby', 'sport', 'talent'].indexOf(category) === -1) { errors.push('Invalid category selected'); markHobbyError('category', 'Select a valid category'); }

        // Check for duplicate in current data
        if (hobbyName && category && window._hobbiesData) {
          var editId = (isEditMode() && window._editingRecord.type === 'hobby') ? window._editingRecord.id : null;
          var duplicate = window._hobbiesData.find(function(h) { return h.name.toLowerCase() === hobbyName.toLowerCase() && h.category === category && h.id !== editId; });
          if (duplicate) { errors.push('This ' + category + ' already exists'); markHobbyError('name', 'Already exists in ' + category); }
        }

        if (errors.length > 0) { showToast(errors[0], 'error'); var firstErr = panel.querySelector('.is-invalid'); if (firstErr) firstErr.focus(); return; }

        var payload = { name: hobbyName, category: category };
        try {
          if (isEditMode() && window._editingRecord.type === 'hobby') {
            await ci4Api('PUT', '/profile/hobbies/' + window._editingRecord.id, payload);
            clearEditMode();
          } else {
            await ci4Api('POST', '/profile/hobbies', payload);
          }
          showToast('Saved successfully', 'success');
          closeOffcanvas('oC_hobbie-sports-talent');
          resetForm('oC_hobbie-sports-talent');
          // Live refresh
          var refreshRes = await ci4Api('GET', '/profile/hobbies').catch(function() { return { data: [] }; });
          window._hobbiesData = (refreshRes && refreshRes.data) || [];
          populateHobbiesDisplay(window._hobbiesData);
        } catch (err) { showToast(err.message || 'Save failed', 'error'); }
      });
    }

