    // ════════════════════════════════════════════
    // 13. Save Patent (CI4 backend)
    // ════════════════════════════════════════════
    var btnSavePatent = document.getElementById('btn-save-patent');
    if (btnSavePatent) {
      btnSavePatent.addEventListener('click', async function(e) {
        e.preventDefault();
        var panel = document.getElementById('oC_patent');
        if (!panel) return;
        function getPVal(name) { var el = panel.querySelector('[name="' + name + '"]'); return el ? el.value.trim() : ''; }

        // Clear previous errors
        panel.querySelectorAll('.is-invalid').forEach(function(el) { el.classList.remove('is-invalid'); el.title = ''; });
        function markPatentError(name, msg) {
          var el = panel.querySelector('[name="' + name + '"]');
          if (el) { el.classList.add('is-invalid'); el.title = msg; el.addEventListener('input', function() { this.classList.remove('is-invalid'); this.title = ''; }, { once: true }); el.addEventListener('change', function() { this.classList.remove('is-invalid'); this.title = ''; }, { once: true }); }
        }

        var title = getPVal('title');
        var description = getPVal('description');
        var status = getPVal('status');
        var patentNumber = getPVal('patent_number');
        var rewardAmount = getPVal('reward_amount');
        var rawDate = getPVal('filing_date') || (panel.querySelector('#patentFilingDate') ? panel.querySelector('#patentFilingDate').value.trim() : '');
        var errors = [];

        if (!title) { errors.push('Title is required'); markPatentError('title', 'Required'); }
        else if (title.length > 255) { errors.push('Title is too long (max 255)'); markPatentError('title', 'Max 255 characters'); }
        if (!description) { errors.push('Description is required'); markPatentError('description', 'Required'); }
        else if (description.length > 1000) { errors.push('Description is too long (max 1000)'); markPatentError('description', 'Max 1000 characters'); }
        if (rewardAmount && isNaN(parseFloat(rewardAmount))) { errors.push('Reward must be a number'); markPatentError('reward_amount', 'Must be a number'); }

        // Validate & convert date: mm/dd/yyyy → YYYY-MM-DD
        var filingDateDb = '';
        if (rawDate) {
          var parts = rawDate.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
          if (parts) {
            filingDateDb = parts[3] + '-' + parts[1].padStart(2, '0') + '-' + parts[2].padStart(2, '0');
          } else if (/^\d{4}-\d{2}-\d{2}$/.test(rawDate)) {
            filingDateDb = rawDate;
          } else {
            errors.push('Invalid date format'); markPatentError('filing_date', 'Invalid date');
          }
          if (filingDateDb) {
            var d = new Date(filingDateDb + 'T00:00:00');
            if (isNaN(d.getTime())) { errors.push('Invalid date'); markPatentError('filing_date', 'Invalid date'); }
          }
        }

        if (errors.length > 0) { showToast(errors[0], 'error'); var firstErr = panel.querySelector('.is-invalid'); if (firstErr) firstErr.focus(); return; }

        var payload = {
          title: title,
          description: description,
          filing_date: filingDateDb,
          status: status || 'Pending',
          patent_number: patentNumber,
          reward_amount: rewardAmount || null
        };
        try {
          if (isEditMode() && _editingRecord.type === 'patent') {
            await ci4Api('PUT', '/profile/patents/' + _editingRecord.id, payload);
            clearEditMode();
          } else {
            await ci4Api('POST', '/profile/patents', payload);
          }
          showToast('Patent saved', 'success');
          closeOffcanvas('oC_patent');
          resetForm('oC_patent');
          var ptTitle = document.getElementById('patent-form-title');
          if (ptTitle) ptTitle.textContent = 'Add Patent';
          // Live refresh patents
          var refreshRes = await ci4Api('GET', '/profile/patents').catch(function() { return { data: [] }; });
          window._patentsData = (refreshRes && refreshRes.data) || [];
          populatePatentsDisplay(window._patentsData);
        } catch (err) { showToast(err.message || 'Save failed', 'error'); }
      });
    }

