    // ════════════════════════════════════════════
    // 17. Save/Update/Delete Feedback (CI4 backend)
    // ════════════════════════════════════════════
    // Global functions for feedback CRUD
    window.addNewFeedback = function() {
      clearEditMode();
      var titleEl = document.getElementById('fb-form-title');
      if (titleEl) titleEl.textContent = 'Add Feedback';
      // Reset form fields
      ['fb-feedback-type','fb-feedback-period','fb-rating','fb-strengths','fb-areas','fb-suggestions','fb-overall-comment'].forEach(function(id) {
        var el = document.getElementById(id);
        if (el) el.value = '';
      });
      var anonEl = document.getElementById('fb-is-anonymous');
      if (anonEl) anonEl.checked = false;
      openOffcanvas('oC_feedback-checkins');
    };

    window.editFeedbackItem = function(id) {
      var fb = (window._feedbackData || []).find(function(f) { return parseInt(f.id) === parseInt(id); });
      if (!fb) { showToast('Feedback record not found', 'error'); return; }
      setEditMode('feedback', id);
      var titleEl = document.getElementById('fb-form-title');
      if (titleEl) titleEl.textContent = 'Edit Feedback';
      // Populate form
      var typeEl = document.getElementById('fb-feedback-type');
      if (typeEl) typeEl.value = fb.feedback_type || '';
      var periodEl = document.getElementById('fb-feedback-period');
      if (periodEl) periodEl.value = fb.feedback_period || '';
      var ratingEl = document.getElementById('fb-rating');
      if (ratingEl) ratingEl.value = fb.rating || '';
      var strengthsEl = document.getElementById('fb-strengths');
      if (strengthsEl) strengthsEl.value = fb.strengths || '';
      var areasEl = document.getElementById('fb-areas');
      if (areasEl) areasEl.value = fb.areas_for_improvement || '';
      var suggestionsEl = document.getElementById('fb-suggestions');
      if (suggestionsEl) suggestionsEl.value = fb.suggestions || '';
      var commentEl = document.getElementById('fb-overall-comment');
      if (commentEl) commentEl.value = fb.overall_comment || '';
      var anonEl = document.getElementById('fb-is-anonymous');
      if (anonEl) anonEl.checked = fb.is_anonymous == 1;
      openOffcanvas('oC_feedback-checkins');
    };

    window.deleteFeedbackItem = function(id) {
      if (!confirm('Are you sure you want to delete this feedback?')) return;
      (async function() {
        try {
          await ci4Api('DELETE', '/performance/feedback/' + id);
          showToast('Feedback deleted', 'success');
          // Remove card from DOM
          var card = document.getElementById('fb-card-' + id);
          if (card) card.remove();
          // Remove from cached data
          if (window._feedbackData) {
            window._feedbackData = window._feedbackData.filter(function(f) { return parseInt(f.id) !== parseInt(id); });
          }
          invalidateCache('talent');
        } catch (err) { showToast(err.message || 'Delete failed', 'error'); }
      })();
    };

    // Save button handler
    (function() {
      var saveBtn = document.getElementById('fb-save-btn');
      if (!saveBtn) return;
      saveBtn.addEventListener('click', async function(e) {
        e.preventDefault();
        var feedbackType = (document.getElementById('fb-feedback-type') || {}).value || '';
        var strengths = (document.getElementById('fb-strengths') || {}).value || '';
        if (!feedbackType) { showToast('Please select a feedback type', 'error'); return; }
        if (!strengths) { showToast('Please enter strengths', 'error'); return; }

        var userId = (window._userData && window._userData.id) || (typeof CURRENT_USER !== 'undefined' && CURRENT_USER ? CURRENT_USER.id : 0);
        var ratingVal = (document.getElementById('fb-rating') || {}).value || '';
        var payload = {
          employee_id: parseInt(userId) || 0,
          feedback_type: feedbackType,
          feedback_period: (document.getElementById('fb-feedback-period') || {}).value || '',
          strengths: strengths,
          areas_for_improvement: (document.getElementById('fb-areas') || {}).value || '',
          suggestions: (document.getElementById('fb-suggestions') || {}).value || '',
          overall_comment: (document.getElementById('fb-overall-comment') || {}).value || '',
          is_anonymous: document.getElementById('fb-is-anonymous') && document.getElementById('fb-is-anonymous').checked ? 1 : 0,
          status: 'Submitted'
        };
        // Only include rating if provided
        if (ratingVal !== '') payload.rating = parseFloat(ratingVal);

        try {
          if (isEditMode() && _editingRecord.type === 'feedback') {
            await ci4Api('PUT', '/performance/feedback/' + _editingRecord.id, payload);
            clearEditMode();
          } else {
            await ci4Api('POST', '/performance/feedback', payload);
          }
          showToast('Feedback saved', 'success');
          closeOffcanvas('oC_feedback-checkins');
          // Reset form
          ['fb-feedback-type','fb-feedback-period','fb-rating','fb-strengths','fb-areas','fb-suggestions','fb-overall-comment'].forEach(function(id) {
            var el = document.getElementById(id);
            if (el) el.value = '';
          });
          var anonEl = document.getElementById('fb-is-anonymous');
          if (anonEl) anonEl.checked = false;
          invalidateCache('talent');
          // Reload the talent tab to refresh feedback cards
          if (typeof loadTalentData === 'function') {
            window._loadedTabs = window._loadedTabs || {};
            window._loadedTabs['talent'] = false;
            loadTalentData(window._currentEmpId || empId);
          }
        } catch (err) { showToast(err.message || 'Save failed', 'error'); }
      });
    })();

    // ════════════════════════════════════════════
    // 18. Save Training (CI4 backend)
    // ════════════════════════════════════════════
    (function() {
      var saveBtn = document.getElementById('btn-save-training');
      if (!saveBtn) return;
      saveBtn.addEventListener('click', async function(e) {
        e.preventDefault();
        var name = document.getElementById('th-training-name');
        var type = document.getElementById('th-training-type');
        var provider = document.getElementById('th-provider');
        var date = document.getElementById('th-training-date');
        var hours = document.getElementById('th-duration-hours');
        var mode = document.getElementById('th-mode');
        var cert = document.getElementById('th-certificate-obtained');

        if (!name || !name.value.trim()) { showToast('Please enter training name', 'error'); return; }
        if (!provider || !provider.value.trim()) { showToast('Please enter provider', 'error'); return; }

        var payload = {
          training_name: name.value.trim(),
          training_type: type ? ($(type).val() || 'Other') : 'Other',
          training_provider: provider.value.trim(),
          training_date: (function() {
            if (!date || !date.value) return '';
            var raw = date.value.trim();
            // Already YYYY-MM-DD
            if (/^\d{4}-\d{2}-\d{2}$/.test(raw)) return raw;
            // Parse "MMM, YYYY" or "MMM YYYY"
            var m = raw.match(/^(\w+)[,\s]+(\d{4})$/);
            if (m) {
              var months = {Jan:'01',Feb:'02',Mar:'03',Apr:'04',May:'05',Jun:'06',Jul:'07',Aug:'08',Sep:'09',Oct:'10',Nov:'11',Dec:'12'};
              var mon = months[m[1]] || '01';
              return m[2] + '-' + mon + '-01';
            }
            return raw;
          })(),
          duration_hours: hours ? parseInt(hours.value) || 0 : 0,
          mode: mode ? ($(mode).val() || 'Online') : 'Online',
          certificate_obtained: cert && cert.checked ? 1 : 0
        };

        try {
          var method = isEditMode() ? 'PUT' : 'POST';
          var url = isEditMode() ? '/learning/training-history/' + _editingRecord.id : '/learning/training-history';
          await ci4Api(method, url, payload);
          showToast('Training ' + (isEditMode() ? 'updated' : 'saved') + ' successfully', 'success');
          closeOffcanvas('oC_add-training');
          resetForm('oC_add-training');
          clearEditMode();
          invalidateCache('jobOrg');
          _loadedTabs['jobOrg'] = false;
          loadJobOrgData(empId);
        } catch (err) { showToast(err.message || 'Save failed', 'error'); }
      });
    })();

    // ── Training CRUD helpers ──
    window.addTraining = function() {
      clearEditMode();
      resetForm('oC_add-training');
      var title = document.getElementById('oC_add-training-title');
      if (title) title.textContent = 'Add Training';
      openOffcanvas('oC_add-training');
    };

    window.editTraining = function(id) {
      var items = window._trainingHistoryData || [];
      var rec = items.find(function(t) { return t.id == id; });
      if (!rec) { showToast('Record not found', 'error'); return; }

      setEditMode('training-history', id, rec);
      var title = document.getElementById('oC_add-training-title');
      if (title) title.textContent = 'Edit Training';

      var el;
      el = document.getElementById('th-training-name'); if (el) el.value = rec.training_name || '';
      el = document.getElementById('th-training-type'); if (el) { $(el).val(rec.training_type || '').trigger('change'); }
      el = document.getElementById('th-provider'); if (el) el.value = rec.training_provider || '';
      el = document.getElementById('th-training-date');
      if (el) {
        var rawDate = rec.training_date || '';
        if (rawDate && /^\d{4}-\d{2}/.test(rawDate)) {
          var dp = new Date(rawDate + 'T00:00:00');
          if (!isNaN(dp.getTime())) {
            rawDate = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'][dp.getMonth()] + ', ' + dp.getFullYear();
          }
        }
        el.value = rawDate;
      }
      el = document.getElementById('th-duration-hours'); if (el) el.value = rec.duration_hours || 0;
      el = document.getElementById('th-mode'); if (el) { $(el).val(rec.mode || '').trigger('change'); }
      el = document.getElementById('th-certificate-obtained'); if (el) el.checked = rec.certificate_obtained == 1;

      openOffcanvas('oC_add-training');
    };

    window.deleteTraining = function(id) {
      if (!confirm('Delete this training record?')) return;
      ci4Api('DELETE', '/learning/training-history/' + id).then(function() {
        showToast('Training deleted', 'success');
        invalidateCache('jobOrg');
        _loadedTabs['jobOrg'] = false;
        loadJobOrgData(empId);
      }).catch(function(err) { showToast(err.message || 'Delete failed', 'error'); });
    };

    // ════════════════════════════════════════════
    // 18b. Certification CRUD helpers
    // ════════════════════════════════════════════
    window.addCertification = function() {
      clearEditMode();
      resetForm('oC_add-certificate');
      var title = document.getElementById('oC_add-certificate-title');
      if (title) title.textContent = 'Add Certification';
      openOffcanvas('oC_add-certificate');
    };

    window.editCertification = function(id) {
      var items = window._certificationData || [];
      var rec = null;
      for (var i = 0; i < items.length; i++) {
        if (String(items[i].certification_id) === String(id) || String(items[i].id) === String(id)) { rec = items[i]; break; }
      }
      if (!rec) { showToast('Certification not found', 'error'); return; }
      setEditMode('certification', id, rec);
      var title = document.getElementById('oC_add-certificate-title');
      if (title) title.textContent = 'Edit Certification';

      var el;
      el = document.getElementById('cert-name'); if (el) el.value = rec.certificate_name || '';
      el = document.getElementById('cert-issuer'); if (el) el.value = rec.grade || '';
      el = document.getElementById('cert-grade'); if (el) el.value = rec.grade || '';

      // Convert dates YYYY-MM-DD → MMM, YYYY
      function toDisplay(d) {
        if (!d || d === '0000-00-00') return '';
        var dt = new Date(d + 'T00:00:00');
        if (isNaN(dt.getTime())) return '';
        var months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
        return months[dt.getMonth()] + ', ' + dt.getFullYear();
      }
      el = document.getElementById('cert-start-date'); if (el) el.value = toDisplay(rec.start_date);
      el = document.getElementById('cert-end-date'); if (el) el.value = toDisplay(rec.end_date);
      el = document.getElementById('cert-cost'); if (el) el.value = rec.cost && parseFloat(rec.cost) > 0 ? rec.cost : '';

      openOffcanvas('oC_add-certificate');
    };

    window.deleteCertification = function(id) {
      if (!confirm('Delete this certification?')) return;
      ci4Api('DELETE', '/hrms-data/certifications/' + id, {hrms_original_id: id}).then(function(resp) {
        showToast('Certification deleted', 'success');
        invalidateCache('jobOrg');
        window._loadedTabs['jobOrg'] = false;
        loadJobOrgData(empId);
      }).catch(function(err) { showToast('Error deleting certification', 'error'); console.error(err); });
    };

