          critical_experiences: (document.getElementById('sp-critical-exp') || {}).value || '',
          gaps: (document.getElementById('sp-gaps') || {}).value || '',
          development_plan: (document.getElementById('sp-dev-plan') || {}).value || '',
          review_date: (document.getElementById('sp-review-date') || {}).value || null,
          notes: (document.getElementById('sp-notes') || {}).value || ''
        };
        if (!payload.review_date) delete payload.review_date;

        try {
          if (isEditMode() && _editingRecord.type === 'succession_plan') {
            await ci4Api('PUT', '/talent/succession/' + _editingRecord.id, payload);
