    window.addTransfer = function() {
      clearEditMode();
      document.getElementById('oC_transfer-title').textContent = 'Add Transfer';
      document.getElementById('tf-transfer-type').value = 'Departmental';
      document.getElementById('tf-prev-dept').value = '';
      document.getElementById('tf-new-dept').value = '';
      document.getElementById('tf-prev-location').value = '';
      document.getElementById('tf-new-location').value = '';
      document.getElementById('tf-transfer-date').value = '';
      document.getElementById('tf-effective-date').value = '';
      document.getElementById('tf-reason').value = '';
      document.getElementById('tf-achievement').value = '';
      document.getElementById('tf-skills').value = '';
      document.getElementById('tf-approval-status').value = 'Approved';
      openOffcanvas('oC_transfer');
    };

    window.editTransfer = function(id) {
      var rec = (window._transfersData || []).find(function(t) { return t.id == id; });
      if (!rec) { showToast('Transfer not found', 'error'); return; }
      setEditMode('transfer', id);
      document.getElementById('oC_transfer-title').textContent = 'Edit Transfer';
      document.getElementById('tf-transfer-type').value = rec.transfer_type || 'Departmental';
      document.getElementById('tf-prev-dept').value = rec.previous_department || '';
      document.getElementById('tf-new-dept').value = rec.new_department || '';
      document.getElementById('tf-prev-location').value = rec.previous_location || '';
      document.getElementById('tf-new-location').value = rec.new_location || '';
      document.getElementById('tf-transfer-date').value = rec.transfer_date || '';
      document.getElementById('tf-effective-date').value = rec.effective_date || '';
      document.getElementById('tf-reason').value = rec.transfer_reason || '';
      document.getElementById('tf-achievement').value = rec.key_achievement || '';
      document.getElementById('tf-skills').value = rec.skills_gained || '';
      document.getElementById('tf-approval-status').value = rec.approval_status || 'Approved';
      openOffcanvas('oC_transfer');
    };

    window.deleteTransfer = function(id) {
      if (!confirm('Delete this transfer record?')) return;
      ci4Api('DELETE', '/job/transfers/' + id).then(function() {
        showToast('Transfer deleted', 'success');
        var card = document.getElementById('tf-card-' + id);
        if (card) card.remove();
        invalidateCache('talent');
        window._loadedTabs['talent'] = false;
        loadTalentData(window._currentEmpId || empId);
      }).catch(function(err) { showToast(err.message || 'Delete failed', 'error'); });
    };

    (function() {
      var saveBtn = document.getElementById('btn-save-transfer');
      if (!saveBtn) return;
      saveBtn.addEventListener('click', async function(e) {
        e.preventDefault();
        e.stopPropagation();

        var prevDept = document.getElementById('tf-prev-dept').value.trim();
        var newDept = document.getElementById('tf-new-dept').value.trim();
        var transferDate = document.getElementById('tf-transfer-date').value;
        if (!prevDept || !newDept) { showToast('Previous and New Department are required', 'error'); return; }
        if (!transferDate) { showToast('Transfer date is required', 'error'); return; }

        var payload = {
          transfer_type: document.getElementById('tf-transfer-type').value,
          previous_department: prevDept,
          new_department: newDept,
          previous_location: document.getElementById('tf-prev-location').value.trim(),
          new_location: document.getElementById('tf-new-location').value.trim(),
          transfer_date: transferDate,
          effective_date: document.getElementById('tf-effective-date').value || null,
          transfer_reason: document.getElementById('tf-reason').value.trim(),
          key_achievement: document.getElementById('tf-achievement').value.trim(),
          skills_gained: document.getElementById('tf-skills').value.trim(),
          approval_status: document.getElementById('tf-approval-status').value
        };

        try {
          if (isEditMode() && _editingRecord.type === 'transfer') {
            await ci4Api('PUT', '/job/transfers/' + _editingRecord.id, payload);
            showToast('Transfer updated', 'success');
          } else {
            await ci4Api('POST', '/job/transfers', payload);
            showToast('Transfer added', 'success');
          }
          closeOffcanvas('oC_transfer');
          clearEditMode();
          invalidateCache('talent');
          window._loadedTabs['talent'] = false;
          loadTalentData(window._currentEmpId || empId);
