    // ════════════════════════════════════════════
    (function() {
      var saveBtn = document.getElementById('btn-save-idp-goal');
      if (!saveBtn) return;
      saveBtn.addEventListener('click', async function(e) {
        e.preventDefault();
        e.stopPropagation();

        var goalTitle = (document.getElementById('idp-goal-title') || {}).value || '';
        if (!goalTitle.trim()) { showToast('Please enter a goal title', 'error'); return; }

        var startDate = (document.getElementById('idp-goal-start-date') || {}).value || '';
        var endDate = (document.getElementById('idp-goal-end-date') || {}).value || '';
        var currentYear = new Date().getFullYear();

        // Default start/end to current year if empty
        if (!startDate) startDate = currentYear + '-01-01';
        if (!endDate) endDate = currentYear + '-12-31';

        var weightVal = (document.getElementById('idp-goal-weightage') || {}).value;
        var progressVal = (document.getElementById('idp-goal-progress') || {}).value;
        var payload = {
          goal_title: goalTitle.trim(),
          goal_description: (document.getElementById('idp-goal-description') || {}).value || '',
          goal_category: (document.getElementById('idp-goal-category') || {}).value || '',
          status: (document.getElementById('idp-goal-status') || {}).value || 'Not Started',
          start_date: startDate,
          end_date: endDate,
          target_value: (document.getElementById('idp-goal-target') || {}).value || '',
          measurement_criteria: (document.getElementById('idp-goal-criteria') || {}).value || ''
        };
        if (weightVal !== '' && weightVal !== undefined) payload.weightage = parseFloat(weightVal);
        if (progressVal !== '' && progressVal !== undefined) payload.progress_percentage = parseInt(progressVal);
        else payload.progress_percentage = 0;

        try {
          if (isEditMode() && window._editingRecord.type === 'idpgoal') {
            await ci4Api('PUT', '/performance/goals/' + window._editingRecord.id, payload);
            clearEditMode();
          } else {
            await ci4Api('POST', '/performance/goals', payload);
          }
          showToast('IDP goal saved', 'success');
          closeOffcanvas('oC_add-IDP-goal');
          resetForm('oC_add-IDP-goal');
          invalidateCache('jobOrg');
          window._loadedTabs['jobOrg'] = false;
          loadJobOrgData(window._currentEmpId || empId);
        } catch (err) {
          console.error('IDP goal save error:', err);
          showToast(err.message || 'Save failed', 'error');
        }
      });

      // CRUD helper functions
      window.addIdpGoal = function() {
        clearEditMode();
        var title = document.getElementById('idp-goal-form-title');
        if (title) title.textContent = 'Add IDP Goal';
        resetForm('oC_add-IDP-goal');
