        el = document.getElementById('idp-goal-description'); if (el) el.value = rec.goal_description || '';
        el = document.getElementById('idp-goal-category'); if (el) el.value = rec.goal_category || '';
        el = document.getElementById('idp-goal-status'); if (el) el.value = rec.status || '';
        el = document.getElementById('idp-goal-target'); if (el) el.value = rec.target_value || '';
        el = document.getElementById('idp-goal-weightage'); if (el) el.value = rec.weightage || '';
        el = document.getElementById('idp-goal-progress'); if (el) el.value = rec.progress_percentage || '';
        el = document.getElementById('idp-goal-criteria'); if (el) el.value = rec.measurement_criteria || '';

