<!-- Global Search + Photo Upload -->
<script>
(function() {
  'use strict';

  // ============================================================
  // Global Search
  // ============================================================
  var searchInput = document.getElementById('global-search-input');
  var searchResults = document.getElementById('global-search-results');
  var searchTimer = null;

  if (searchInput && searchResults) {
    searchInput.addEventListener('input', function() {
      clearTimeout(searchTimer);
      var q = this.value.trim();
      if (q.length < 2) {
        searchResults.classList.add('d-none');
        searchResults.innerHTML = '';
        return;
      }
      searchTimer = setTimeout(function() { performSearch(q); }, 300);
    });

    searchInput.addEventListener('focus', function() {
      if (searchResults.innerHTML.trim()) searchResults.classList.remove('d-none');
    });

    document.addEventListener('click', function(e) {
      if (!searchInput.contains(e.target) && !searchResults.contains(e.target)) {
        searchResults.classList.add('d-none');
      }
    });
  }

  async function performSearch(q) {
    try {
      var resp = await ci4Api('GET', '/search/global?q=' + encodeURIComponent(q) + '&limit=5');
      if (!resp || !resp.data) return;
      var data = resp.data;
      var html = '';

      // Employees
      if (data.employees && data.employees.length > 0) {
        html += '<div class="px-4 py-2 bg-light border-bottom"><small class="font-weight-bold text-muted text-uppercase">Employees</small></div>';
        data.employees.forEach(function(emp) {
          var name = (emp.first_name || '') + ' ' + (emp.last_name || '');
          var sub = [emp.designation, emp.department].filter(Boolean).join(' - ');
          html += '<a href="#" class="d-flex align-items-center px-4 py-3 border-bottom text-dark text-hover-primary" onclick="searchSelectEmployee(\'' + emp.employee_id + '\');return false;">';
          html += '<div class="symbol symbol-30 symbol-light-primary mr-3"><div class="symbol-label font-weight-bold">' + (emp.first_name ? emp.first_name.charAt(0) : '?') + '</div></div>';
          html += '<div><div class="font-weight-bold font-13">' + name.trim() + '</div>';
          if (sub) html += '<div class="text-muted font-12">' + sub + '</div>';
          html += '</div></a>';
        });
      }

      // Skills
      if (data.skills && data.skills.length > 0) {
        html += '<div class="px-4 py-2 bg-light border-bottom"><small class="font-weight-bold text-muted text-uppercase">Skills</small></div>';
        data.skills.forEach(function(s) {
          html += '<div class="d-flex align-items-center px-4 py-2 border-bottom">';
          html += '<span class="label label-inline label-light-info mr-3 font-12">' + (s.skill_category || 'Skill') + '</span>';
          html += '<span class="font-13">' + (s.skill_name || '') + '</span>';
          html += '</div>';
        });
      }

      // Courses
      if (data.courses && data.courses.length > 0) {
        html += '<div class="px-4 py-2 bg-light border-bottom"><small class="font-weight-bold text-muted text-uppercase">Courses</small></div>';
        data.courses.forEach(function(c) {
          html += '<div class="d-flex align-items-center px-4 py-2 border-bottom">';
          html += '<span class="label label-inline label-light-warning mr-3 font-12">' + (c.course_type || 'Course') + '</span>';
          html += '<span class="font-13">' + (c.course_name || '') + '</span>';
          html += '</div>';
        });
      }

      if (!html) {
        html = '<div class="px-4 py-3 text-muted font-13 text-center">No results found</div>';
      }

      searchResults.innerHTML = html;
      searchResults.classList.remove('d-none');
    } catch (err) {
      console.error('Search error:', err);
    }
  }

  // When an employee is selected from search, reload profile
  window.searchSelectEmployee = function(empId) {
    searchResults.classList.add('d-none');
    searchInput.value = '';
    // Reload page with the selected employee's data
    window.location.href = 'index.php?emp_id=' + encodeURIComponent(empId);
  };

  // ============================================================
  // Photo Upload — uploads to HRMS directory via photo_upload.php
  // ============================================================
  var photoInput = document.getElementById('photo-upload-input');
  if (photoInput) {
    photoInput.addEventListener('change', async function() {
      var file = this.files[0];
      if (!file) return;

      // Validate client-side
      var allowed = ['image/jpeg', 'image/png', 'image/webp', 'image/gif'];
      if (allowed.indexOf(file.type) === -1) {
        showToast('Only JPEG, PNG, WebP, and GIF images are allowed', 'error');
        this.value = '';
        return;
      }
      if (file.size > 2 * 1024 * 1024) {
        showToast('File size must not exceed 2MB', 'error');
        this.value = '';
        return;
      }

      // Show loading state on avatar
      var avatarEl = document.getElementById('profile-avatar');
      if (avatarEl) avatarEl.style.opacity = '0.5';

      try {
        var formData = new FormData();
        formData.append('file', file);

        var res = await fetch('photo_upload.php', {
          method: 'POST',
          headers: { 'X-CSRF-Token': getCsrfToken() },
          body: formData
        });

        var data = await res.json();
        if (!res.ok || data.status !== 'success') {
          throw new Error(data.message || 'Upload failed');
        }

        // Update avatar with new URL (add cache-buster)
        if (avatarEl && data.url) {
          avatarEl.style.backgroundImage = "url('" + data.url + '?t=' + Date.now() + "')";
        }
        // Also update header avatar if exists
        var headerAvatar = document.getElementById('header-user-avatar');
        if (headerAvatar && data.url) {
          headerAvatar.style.backgroundImage = "url('" + data.url + '?t=' + Date.now() + "')";
        }
        showToast('Profile photo updated', 'success');
      } catch (err) {
        showToast(err.message || 'Photo upload failed', 'error');
      }

      if (avatarEl) avatarEl.style.opacity = '1';
      // Reset file input
      this.value = '';
    });
  }
})();
</script>
</body>
<!--end::Body-->

</html>